{
  "name": "JapanTrip Planner - 日本旅遊規劃大師",
  "description": "A comprehensive travel planning application designed with a Japanese modern minimalist aesthetic. Features include itinerary management with drag-and-drop, budget tracking, weather integration, and a travel toolbox with currency conversion and checklists."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ActivityType {
  FOOD = 'Food',
  SIGHTSEEING = 'Sightseeing',
  TRANSPORT = 'Transport',
  HOTEL = 'Hotel',
  SHOPPING = 'Shopping'
}

export interface Activity {
  id: string;
  time: string;
  type: ActivityType;
  location: string;
  note?: string;
  cost: number;
}

export interface DailyItinerary {
  day: number;
  date: string;
  weather?: {
    condition: 'Sunny' | 'Cloudy' | 'CloudSun' | 'Rain' | 'Snow';
    tempMin: number;
    tempMax: number;
  };
  activities: Activity[];
}

export interface ChecklistItem {
  id: string;
  item: string;
  completed: boolean;
}

export interface TripBudget {
  total: number;
  spent: number;
}

export interface Trip {
  id: string;
  title: string;
  startDate: string;
  endDate: string;
  status: 'planning' | 'ongoing' | 'completed';
  coverImage: string;
  dailyItinerary: DailyItinerary[];
  budget: TripBudget;
  checklist: ChecklistItem[];
}

export interface AppState {
  trips: Trip[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import TripDetail from './pages/TripDetail';
import BudgetPage from './pages/Budget';
import Toolbox from './pages/Toolbox';
import { TripProvider } from './store/TripContext';

const App: React.FC = () => {
  return (
    <TripProvider>
      <Router>
        <Layout>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/trip/:tripId" element={<TripDetail />} />
            <Route path="/budget/:tripId" element={<BudgetPage />} />
            <Route path="/toolbox/:tripId" element={<Toolbox />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </Layout>
      </Router>
    </TripProvider>
  );
};

export default App;

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Trip, AppState, Activity } from '../types';

interface TripContextType {
  trips: Trip[];
  addTrip: (trip: Trip) => void;
  updateTrip: (trip: Trip) => void;
  deleteTrip: (id: string) => void;
  getTripById: (id: string) => Trip | undefined;
}

const TripContext = createContext<TripContextType | undefined>(undefined);

const STORAGE_KEY = 'japan_trip_planner_data';

const initialData: Trip[] = [
  {
    id: '1',
    title: '2026 東京之行',
    startDate: '2026-03-25',
    endDate: '2026-04-02',
    status: 'planning',
    coverImage: 'https://picsum.photos/seed/tokyo/800/400',
    dailyItinerary: [
      {
        day: 1,
        date: '2026-03-25',
        weather: { condition: 'CloudSun', tempMin: 12, tempMax: 18 },
        activities: [
          { id: 'a1', time: '10:00', type: 'Sightseeing' as any, location: '淺草寺', cost: 0, note: '雷門拍照' },
          { id: 'a2', time: '12:30', type: 'Food' as any, location: '一蘭拉麵', cost: 1500 }
        ]
      }
    ],
    budget: { total: 200000, spent: 1500 },
    checklist: [
      { id: 'c1', item: 'JR Pass', completed: false },
      { id: 'c2', item: '護照', completed: true }
    ]
  }
];

export const TripProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [trips, setTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : initialData;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(trips));
  }, [trips]);

  const addTrip = useCallback((trip: Trip) => {
    setTrips(prev => [...prev, trip]);
  }, []);

  const updateTrip = useCallback((updatedTrip: Trip) => {
    setTrips(prev => prev.map(t => t.id === updatedTrip.id ? updatedTrip : t));
  }, []);

  const deleteTrip = useCallback((id: string) => {
    setTrips(prev => prev.filter(t => t.id !== id));
  }, []);

  const getTripById = useCallback((id: string) => {
    return trips.find(t => t.id === id);
  }, [trips]);

  return (
    <TripContext.Provider value={{ trips, addTrip, updateTrip, deleteTrip, getTripById }}>
      {children}
    </TripContext.Provider>
  );
};

export const useTrips = () => {
  const context = useContext(TripContext);
  if (!context) throw new Error('useTrips must be used within a TripProvider');
  return context;
};

import React, { useState } from 'react';
