import React, { useState } from 'react';
import { Plus, Calendar, MapPin, MoreVertical, Trash2, Edit2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useTrips } from '../store/TripContext';
import { Trip } from '../types';
import { motion } from 'framer-motion';

const TripCard: React.FC<{ trip: Trip; onDelete: (id: string) => void }> = ({ trip, onDelete }) => {
  const navigate = useNavigate();
  const [showOptions, setShowOptions] = useState(false);

  const daysDiff = (dateStr: string) => {
    const today = new Date();
    const target = new Date(dateStr);
    const diffTime = target.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const countdown = daysDiff(trip.startDate);
  const totalDays = daysDiff(trip.endDate) - daysDiff(trip.startDate) + 1;

  return (
    <motion.div 
      whileHover={{ y: -5 }}
      className="group bg-white rounded-[2rem] overflow-hidden shadow-sm border border-gray-100 flex flex-col relative"
    >
      <div 
        onClick={() => navigate(`/trip/${trip.id}`)}
        className="cursor-pointer"
      >
        <div className="relative h-48 overflow-hidden">
          <img 
            src={trip.coverImage || 'https://picsum.photos/seed/japan/800/400'} 
            alt={trip.title}
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
          <div className="absolute bottom-4 left-6 text-white">
            <h3 className="text-xl font-bold">{trip.title}</h3>
            <div className="flex items-center gap-1 text-sm text-white/90">
              <Calendar size={14} />
              <span>{trip.startDate} - {trip.endDate}</span>
            </div>
          </div>
          <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md rounded-full px-3 py-1 text-xs text-white font-medium border border-white/30">
            {totalDays} 天
          </div>
        </div>
      </div>

      <div className="p-6 flex-1 flex flex-col justify-between">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2 text-gray-500 text-sm">
            <MapPin size={16} className="text-[#BC002D]" />
            <span>日本</span>
          </div>
          <div className="relative">
            <button 
              onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }}
              className="p-1 hover:bg-gray-100 rounded-full transition-colors"
            >
              <MoreVertical size={20} className="text-gray-400" />
            </button>
            {showOptions && (
              <div className="absolute right-0 bottom-full mb-2 w-32 bg-white rounded-xl shadow-xl border border-gray-100 py-1 z-10">
                <button 
                  onClick={() => onDelete(trip.id)}
                  className="w-full text-left px-4 py-2 text-sm text-red-500 hover:bg-red-50 flex items-center gap-2"
                >
                  <Trash2 size={14} /> 刪除
                </button>
              </div>
            )}
          </div>
        </div>

        <div>
          <div className="flex justify-between items-end mb-2">
            <span className="text-xs font-semibold text-gray-400 uppercase tracking-wider">
              {countdown > 0 ? '距離出發還有' : '旅程進行中'}
            </span>
            <span className="text-lg font-bold text-[#2D3436]">
              {countdown > 0 ? `${countdown} 天` : 'DAY 1'}
            </span>
          </div>
          <div className="h-2 w-full bg-gray-100 rounded-full overflow-hidden">
            <motion.div 
              initial={{ width: 0 }}
              animate={{ width: countdown > 0 ? '0%' : '40%' }}
              className="h-full bg-[#BC002D]"
            />
          </div>
        </div>
      </div>
    </motion.div>
  );
};

const CreateTripModal: React.FC<{ isOpen: boolean; onClose: () => void; onAdd: (t: Trip) => void }> = ({ isOpen, onClose, onAdd }) => {
  const [formData, setFormData] = useState({ title: '', start: '', end: '', image: '' });

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTrip: Trip = {
      id: Math.random().toString(36).substr(2, 9),
      title: formData.title,
      startDate: formData.start,
      endDate: formData.end,
      status: 'planning',
      coverImage: formData.image || `https://picsum.photos/seed/${formData.title}/800/400`,
      dailyItinerary: [],
      budget: { total: 0, spent: 0 },
      checklist: []
    };
    onAdd(newTrip);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
      <motion.div 
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        className="bg-white rounded-[2.5rem] w-full max-w-md p-8 relative shadow-2xl overflow-hidden"
      >
        <div className="absolute top-0 left-0 w-full h-2 bg-[#BC002D]" />
        <h2 className="text-2xl font-bold mb-6 text-[#2D3436]">新旅程 ✨</h2>
        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-medium text-gray-500 mb-2">旅程標題</label>
            <input 
              required
              className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-none focus:ring-2 focus:ring-[#BC002D]/20 transition-all outline-none"
              placeholder="例如：2026 東京櫻花季"
              value={formData.title}
              onChange={e => setFormData({ ...formData, title: e.target.value })}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-500 mb-2">開始日期</label>
              <input 
                required
                type="date"
                className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-none focus:ring-2 focus:ring-[#BC002D]/20 outline-none"
                value={formData.start}
                onChange={e => setFormData({ ...formData, start: e.target.value })}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-500 mb-2">結束日期</label>
              <input 
                required
                type="date"
                className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-none focus:ring-2 focus:ring-[#BC002D]/20 outline-none"
                value={formData.end}
                onChange={e => setFormData({ ...formData, end: e.target.value })}
              />
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-500 mb-2">封面圖片 URL (選填)</label>
            <input 
              className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-none focus:ring-2 focus:ring-[#BC002D]/20 outline-none"
              placeholder="https://..."
              value={formData.image}
              onChange={e => setFormData({ ...formData, image: e.target.value })}
            />
          </div>
          <button 
            type="submit"
            className="w-full py-4 bg-[#2D3436] text-white rounded-2xl font-bold hover:bg-black transition-all shadow-lg shadow-gray-200 mt-4"
          >
            建立旅程
          </button>
        </form>
      </motion.div>
    </div>
  );
};

const Dashboard: React.FC = () => {
  const { trips, addTrip, deleteTrip } = useTrips();
  const [isModalOpen, setIsModalOpen] = useState(false);

  return (
    <div className="space-y-10">
      <div className="flex items-end justify-between">
        <div>
          <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">我的旅程</h1>
          <p className="text-gray-500">開始規劃你的下一趟日本之旅 🌸</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {trips.map(trip => (
          <TripCard key={trip.id} trip={trip} onDelete={deleteTrip} />
        ))}

        <button 
          onClick={() => setIsModalOpen(true)}
          className="group h-[320px] rounded-[2rem] border-2 border-dashed border-gray-200 hover:border-[#BC002D] hover:bg-[#BC002D]/5 flex flex-col items-center justify-center gap-4 transition-all duration-300"
        >
          <div className="p-4 bg-gray-50 group-hover:bg-[#BC002D]/10 rounded-full text-gray-400 group-hover:text-[#BC002D] transition-colors">
            <Plus size={32} />
          </div>
          <span className="text-gray-500 font-bold group-hover:text-[#BC002D]">新增旅程</span>
        </button>
      </div>

      <CreateTripModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onAdd={addTrip}
      />
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Sun, Cloud, CloudSun, CloudRain, CloudSnow, 
  Plus, Utensils, Camera, TrainFront, Hotel, ShoppingBag,
  Clock, MapPin, GripVertical, Trash2
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, ActivityType, Activity, DailyItinerary } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const TypeIcon = ({ type }: { type: ActivityType }) => {
  switch (type) {
    case ActivityType.FOOD: return <Utensils size={18} className="text-orange-500" />;
    case ActivityType.SIGHTSEEING: return <Camera size={18} className="text-blue-500" />;
    case ActivityType.TRANSPORT: return <TrainFront size={18} className="text-green-500" />;
    case ActivityType.HOTEL: return <Hotel size={18} className="text-purple-500" />;
    case ActivityType.SHOPPING: return <ShoppingBag size={18} className="text-pink-500" />;
    default: return <MapPin size={18} className="text-gray-500" />;
  }
};

const WeatherIcon = ({ condition }: { condition?: string }) => {
  switch (condition) {
    case 'Sunny': return <Sun size={20} className="text-yellow-500" />;
    case 'Cloudy': return <Cloud size={20} className="text-gray-400" />;
    case 'CloudSun': return <CloudSun size={20} className="text-orange-400" />;
    case 'Rain': return <CloudRain size={20} className="text-blue-400" />;
    case 'Snow': return <CloudSnow size={20} className="text-indigo-300" />;
    default: return <Sun size={20} className="text-yellow-500" />;
  }
};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newActivity, setNewActivity] = useState<Partial<Activity>>({
    time: '10:00',
    type: ActivityType.SIGHTSEEING,
    location: '',
    note: '',
    cost: 0
  });

  if (!trip) return <div>Trip not found</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const addActivity = () => {
    const activity: Activity = {
      id: Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...trip.dailyItinerary];
    const index = updatedItinerary.findIndex(i => i.day === activeDay);

    if (index > -1) {
      updatedItinerary[index] = {
        ...updatedItinerary[index],
        activities: [...updatedItinerary[index].activities, activity].sort((a, b) => a.time.localeCompare(b.time))
      };
    } else {
      updatedItinerary.push({
        ...currentItinerary,
        activities: [activity]
      });
    }

    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: trip.budget.spent + activity.cost }
    });
    setIsModalOpen(false);
  };

  const deleteActivity = (activityId: string) => {
    const updatedItinerary = trip.dailyItinerary.map(day => {
      if (day.day === activeDay) {
        return {
          ...day,
          activities: day.activities.filter(a => a.id !== activityId)
        };
      }
      return day;
    });

    const activityToDelete = currentItinerary.activities.find(a => a.id === activityId);
    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: Math.max(0, trip.budget.spent - (activityToDelete?.cost || 0)) }
    });
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      {/* Day Selector Sidebar */}
      <aside className="lg:w-72 flex lg:flex-col gap-3 overflow-x-auto pb-4 lg:pb-0 scrollbar-hide">
        {Array.from({ length: 7 }, (_, i) => i + 1).map(dayNum => {
          const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
          const isActive = activeDay === dayNum;

          return (
            <button
              key={dayNum}
              onClick={() => setActiveDay(dayNum)}
              className={`
                flex-shrink-0 flex lg:flex-row flex-col items-center gap-3 lg:gap-4 p-4 lg:px-6 lg:py-4 rounded-2xl transition-all duration-300
                ${isActive 
                  ? 'bg-gradient-to-r from-[#BC002D] to-[#E63946] text-white shadow-lg scale-105' 
