import React from 'react';
import { useParams } from 'react-router-dom';
import { useTrips } from '../store/TripContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Utensils, Camera, TrainFront, Hotel, ShoppingBag, Box, AlertCircle } from 'lucide-react';
import { ActivityType } from '../types';

const COLORS = ['#F97316', '#3B82F6', '#22C55E', '#A855F7', '#EC4899', '#94A3B8'];

const BudgetPage: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  if (!trip) return <div>Trip not found</div>;

  const categorySpending = trip.dailyItinerary.reduce((acc, day) => {
    day.activities.forEach(act => {
      acc[act.type] = (acc[act.type] || 0) + act.cost;
    });
    return acc;
  }, {} as Record<string, number>);

  const data = Object.entries(categorySpending).map(([name, value]) => ({ name, value }));
  const totalSpent = Object.values(categorySpending).reduce((a, b) => a + b, 0);
  const remaining = trip.budget.total - totalSpent;
  const isOverBudget = remaining < 0;

  const categoryIcons: Record<string, any> = {
    [ActivityType.FOOD]: { icon: <Utensils size={18} />, color: 'bg-orange-500' },
    [ActivityType.SIGHTSEEING]: { icon: <Camera size={18} />, color: 'bg-blue-500' },
    [ActivityType.TRANSPORT]: { icon: <TrainFront size={18} />, color: 'bg-green-500' },
    [ActivityType.HOTEL]: { icon: <Hotel size={18} />, color: 'bg-purple-500' },
    [ActivityType.SHOPPING]: { icon: <ShoppingBag size={18} />, color: 'bg-pink-500' },
    'Other': { icon: <Box size={18} />, color: 'bg-slate-400' }
  };

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預算追蹤</h1>
        <p className="text-gray-500">掌握你的旅程開支 💰</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Summary Cards */}
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col justify-between">
            <span className="text-sm font-bold text-gray-400 uppercase tracking-widest">總預算</span>
            <div className="flex items-end gap-3 mt-4">
              <span className="text-4xl font-black text-[#2D3436]">¥ {trip.budget.total.toLocaleString()}</span>
              <button 
                onClick={() => {
                  const newBudget = prompt('請輸入新的總預算:', trip.budget.total.toString());
                  if (newBudget) updateTrip({...trip, budget: {...trip.budget, total: parseInt(newBudget)}});
                }}
                className="text-xs text-[#BC002D] font-bold hover:underline mb-1"
              >
                修改
              </button>
            </div>
          </div>

          <div className={`p-8 rounded-[2.5rem] border shadow-sm flex flex-col justify-between ${isOverBudget ? 'bg-red-50 border-red-100' : 'bg-white border-gray-100'}`}>
            <span className={`text-sm font-bold uppercase tracking-widest ${isOverBudget ? 'text-red-400' : 'text-gray-400'}`}>
              {isOverBudget ? '超出預算' : '剩餘預算'}
            </span>
            <div className="mt-4 flex items-center justify-between">
              <span className={`text-4xl font-black ${isOverBudget ? 'text-red-500' : 'text-[#00A86B]'}`}>
                ¥ {Math.abs(remaining).toLocaleString()}
              </span>
              {isOverBudget && <AlertCircle className="text-red-500" size={32} />}
            </div>
          </div>

          {/* Categories */}
          <div className="md:col-span-2 bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm">
            <h3 className="text-xl font-bold mb-6 text-[#2D3436]">支出類別</h3>
            <div className="space-y-6">
              {Object.keys(ActivityType).map((key, i) => {
                const type = ActivityType[key as keyof typeof ActivityType];
                const amount = categorySpending[type] || 0;
                const percentage = totalSpent > 0 ? (amount / totalSpent) * 100 : 0;
                const info = categoryIcons[type];

                return (
                  <div key={type} className="flex items-center gap-6">
                    <div className={`${info.color} text-white p-3 rounded-2xl shadow-lg shadow-${info.color.split('-')[1]}-200`}>
                      {info.icon}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between mb-2">
                        <span className="font-bold text-[#2D3436]">{type}</span>
                        <span className="font-bold text-gray-500">¥ {amount.toLocaleString()} ({percentage.toFixed(0)}%)</span>
                      </div>
                      <div className="h-2 w-full bg-gray-50 rounded-full overflow-hidden">
                        <motion.div 
                          initial={{ width: 0 }}
                          animate={{ width: `${percentage}%` }}
                          className={`h-full ${info.color}`}
                        />
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col items-center">
          <h3 className="text-xl font-bold mb-2 text-[#2D3436]">開支分佈</h3>
          <p className="text-sm text-gray-400 mb-8">視覺化你的旅行消費</p>
          <div className="w-full h-[300px]">
            {totalSpent > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={data}
                    innerRadius={80}
                    outerRadius={100}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {data.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-gray-300 gap-4">
                <div className="w-40 h-40 rounded-full border-8 border-gray-50 flex items-center justify-center">
                  <span className="text-xs font-bold uppercase tracking-widest">無數據</span>
                </div>
              </div>
            )}
          </div>
          <div className="mt-8 text-center">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest block mb-1">已花費</span>
            <span className="text-3xl font-black text-[#BC002D]">¥ {totalSpent.toLocaleString()}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BudgetPage;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  CheckCircle2, Circle, Plus, Trash2, 
  RefreshCcw, ArrowRightLeft, DollarSign, Info
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { motion } from 'framer-motion';

const Toolbox: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [newItem, setNewItem] = useState('');
  const [jpyAmount, setJpyAmount] = useState('1000');
  const [hkdAmount, setHkdAmount] = useState('55');
  const exchangeRate = 0.051; // Hardcoded mock rate

  useEffect(() => {
    const jpy = parseFloat(jpyAmount);
    if (!isNaN(jpy)) {
      setHkdAmount((jpy * exchangeRate).toFixed(2));
    }
  }, [jpyAmount]);

  if (!trip) return <div>Trip not found</div>;

  const toggleCheck = (id: string) => {
    const updated = trip.checklist.map(item => 
      item.id === id ? { ...item, completed: !item.completed } : item
    );
    updateTrip({ ...trip, checklist: updated });
  };

  const deleteItem = (id: string) => {
    const updated = trip.checklist.filter(item => item.id !== id);
    updateTrip({ ...trip, checklist: updated });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    const item = { id: Math.random().toString(36).substr(2, 9), item: newItem, completed: false };
    updateTrip({ ...trip, checklist: [...trip.checklist, item] });
    setNewItem('');
  };

  const completedCount = trip.checklist.filter(i => i.completed).length;
  const progress = trip.checklist.length > 0 ? (completedCount / trip.checklist.length) * 100 : 0;

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">旅行工具箱</h1>
        <p className="text-gray-500">準備好你的行裝與資金 🧳</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        {/* Checklist */}
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-2xl font-bold text-[#2D3436]">出發前檢查清單</h3>
            <span className="text-sm font-bold bg-[#FFB7C5]/20 text-[#BC002D] px-4 py-1 rounded-full">
              {completedCount} / {trip.checklist.length}
            </span>
          </div>

          <div className="mb-8">
            <div className="flex justify-between text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">
              <span>完成進度</span>
              <span>{progress.toFixed(0)}%</span>
            </div>
            <div className="h-2 w-full bg-gray-50 rounded-full overflow-hidden">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                className="h-full bg-[#BC002D]"
              />
            </div>
          </div>

          <form onSubmit={addItem} className="flex gap-2 mb-8">
            <input 
              className="flex-1 px-6 py-4 rounded-2xl bg-gray-50 outline-none focus:ring-2 focus:ring-[#BC002D]/10"
              placeholder="新增項目..."
              value={newItem}
              onChange={e => setNewItem(e.target.value)}
            />
            <button className="p-4 bg-[#2D3436] text-white rounded-2xl hover:bg-black transition-all">
              <Plus size={24} />
            </button>
          </form>

          <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {trip.checklist.map(item => (
              <div key={item.id} className="group flex items-center justify-between p-4 rounded-2xl hover:bg-gray-50 transition-all">
                <button 
                  onClick={() => toggleCheck(item.id)}
                  className="flex items-center gap-4 flex-1 text-left"
                >
                  {item.completed ? (
                    <CheckCircle2 className="text-[#00A86B]" size={24} />
                  ) : (
                    <Circle className="text-gray-200" size={24} />
                  )}
                  <span className={`font-medium ${item.completed ? 'text-gray-300 line-through' : 'text-[#2D3436]'}`}>
                    {item.item}
                  </span>
                </button>
                <button 
                  onClick={() => deleteItem(item.id)}
                  className="p-2 text-gray-200 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            ))}
            {trip.checklist.length === 0 && (
              <p className="text-center text-gray-400 py-10">清單是空的，加點東西吧！</p>
            )}
          </div>
        </div>

        {/* Currency Converter */}
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-2xl font-bold text-[#2D3436]">匯率轉換</h3>
            <RefreshCcw size={20} className="text-gray-300 animate-spin-slow cursor-pointer hover:text-[#BC002D]" />
          </div>

          <div className="flex-1 flex flex-col justify-center space-y-12">
            <div className="space-y-6">
              <div className="relative">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3 ml-2">日圓 (JPY)</label>
                <div className="flex items-center bg-gray-50 rounded-[2rem] px-8 py-6">
                  <span className="text-3xl font-black text-gray-300 mr-4">¥</span>
                  <input 
                    type="number"
                    className="flex-1 bg-transparent text-4xl font-black text-[#2D3436] outline-none"
                    value={jpyAmount}
                    onChange={e => setJpyAmount(e.target.value)}
                  />
                </div>
              </div>

              <div className="flex justify-center -my-6 relative z-10">
                <div className="bg-[#2D3436] text-white p-4 rounded-full shadow-xl shadow-gray-200 border-4 border-white">
                  <ArrowRightLeft size={24} />
                </div>
              </div>

              <div className="relative">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-3 ml-2">港幣 (HKD)</label>
                <div className="flex items-center bg-gray-50 rounded-[2rem] px-8 py-6">
                  <span className="text-3xl font-black text-gray-300 mr-4">$</span>
                  <input 
                    readOnly
                    className="flex-1 bg-transparent text-4xl font-black text-[#BC002D] outline-none"
                    value={hkdAmount}
                  />
                </div>
              </div>
            </div>

            <div className="bg-blue-50/50 p-6 rounded-3xl border border-blue-100 flex items-start gap-4">
              <Info className="text-blue-400 flex-shrink-0 mt-1" size={20} />
              <div className="text-sm text-blue-800 leading-relaxed">
                當前匯率參考：<span className="font-bold">1 JPY ≈ {exchangeRate} HKD</span>。數據僅供參考，實際請以銀行匯率為準。
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

