const TripCard: React.FC<{ trip: Trip; onDelete: (id: string) => void }> = ({ trip, onDelete }) => {
  const navigate = useNavigate();
  const [showOptions, setShowOptions] = useState(false);

  const daysDiff = (dateStr: string) => {
    const today = new Date();
    const target = new Date(dateStr);
    const diffTime = target.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  const countdown = daysDiff(trip.startDate);
  const totalDays = daysDiff(trip.endDate) - daysDiff(trip.startDate) + 1;

  return (
    <motion.div 
      whileHover={{ y: -5 }}
      className="group bg-white rounded-[2rem] overflow-hidden shadow-sm border border-gray-100 flex flex-col relative"
    >
      <div 
        onClick={() => navigate(`/trip/${trip.id}`)}
        className="cursor-pointer"
      >
        <div className="relative h-48 overflow-hidden">
          <img 
            src={trip.coverImage || 'https://picsum.photos/seed/japan/800/400'} 
            alt={trip.title}
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
          <div className="absolute bottom-4 left-6 text-white">
            <h3 className="text-xl font-bold text-white drop-shadow-md">{trip.title}</h3>
            <div className="flex items-center gap-1 text-sm text-gray-100">
              <Calendar size={14} />
              <span>{trip.startDate} - {trip.endDate}</span>
            </div>
          </div>
          <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md rounded-full px-3 py-1 text-xs text-white font-medium border border-white/30">
            {totalDays} 天
          </div>
        </div>
      </div>

      <div className="p-6 flex-1 flex flex-col justify-between bg-white">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2 text-gray-600 text-sm">
            <MapPin size={16} className="text-[#BC002D]" />
            <span className="font-medium">日本</span>
          </div>
          <div className="relative">
            <button 
              onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }}
              className="p-1 hover:bg-gray-100 rounded-full transition-colors"
            >
              <MoreVertical size={20} className="text-gray-400" />
            </button>
            {showOptions && (
              <div className="absolute right-0 bottom-full mb-2 w-32 bg-white rounded-xl shadow-xl border border-gray-100 py-1 z-10">
                <button 
                  onClick={() => onDelete(trip.id)}
                  className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 flex items-center gap-2 font-medium"
