const TypeIcon = ({ type, contrast = false }: { type: ActivityType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case ActivityType.FOOD: return <Utensils size={18} className={contrast ? baseClass : "text-orange-500"} />;
    case ActivityType.SIGHTSEEING: return <Camera size={18} className={contrast ? baseClass : "text-blue-500"} />;
    case ActivityType.TRANSPORT: return <TrainFront size={18} className={contrast ? baseClass : "text-green-500"} />;
    case ActivityType.HOTEL: return <Hotel size={18} className={contrast ? baseClass : "text-purple-500"} />;
    case ActivityType.SHOPPING: return <ShoppingBag size={18} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <MapPin size={18} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const WeatherIcon = ({ condition, isActive = false }: { condition?: string, isActive?: boolean }) => {
  const baseColor = isActive ? "text-white" : "";
  switch (condition) {
    case 'Sunny': return <Sun size={20} className={isActive ? baseColor : "text-yellow-500"} />;
    case 'Cloudy': return <Cloud size={20} className={isActive ? baseColor : "text-gray-400"} />;
    case 'CloudSun': return <CloudSun size={20} className={isActive ? baseColor : "text-orange-400"} />;
    case 'Rain': return <CloudRain size={20} className={isActive ? baseColor : "text-blue-400"} />;
    case 'Snow': return <CloudSnow size={20} className={isActive ? baseColor : "text-indigo-300"} />;
    default: return <Sun size={20} className={isActive ? baseColor : "text-yellow-500"} />;
  }
};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newActivity, setNewActivity] = useState<Partial<Activity>>({
    time: '10:00',
    type: ActivityType.SIGHTSEEING,
    location: '',
    note: '',
    cost: 0
  });

  if (!trip) return <div>Trip not found</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const addActivity = () => {
    const activity: Activity = {
      id: Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...trip.dailyItinerary];
    const index = updatedItinerary.findIndex(i => i.day === activeDay);

    if (index > -1) {
      updatedItinerary[index] = {
        ...updatedItinerary[index],
        activities: [...updatedItinerary[index].activities, activity].sort((a, b) => a.time.localeCompare(b.time))
      };
    } else {
      updatedItinerary.push({
        ...currentItinerary,
        activities: [activity]
      });
    }

    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: trip.budget.spent + activity.cost }
    });
    setIsModalOpen(false);
  };

  const deleteActivity = (activityId: string) => {
    const updatedItinerary = trip.dailyItinerary.map(day => {
      if (day.day === activeDay) {
        return {
          ...day,
          activities: day.activities.filter(a => a.id !== activityId)
        };
      }
      return day;
    });

    const activityToDelete = currentItinerary.activities.find(a => a.id === activityId);
    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: Math.max(0, trip.budget.spent - (activityToDelete?.cost || 0)) }
    });
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      {/* Day Selector Sidebar */}
      <aside className="lg:w-72 flex lg:flex-col gap-3 overflow-x-auto pb-4 lg:pb-0 scrollbar-hide">
        {Array.from({ length: 7 }, (_, i) => i + 1).map(dayNum => {
          const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
          const isActive = activeDay === dayNum;

          return (
            <button
              key={dayNum}
              onClick={() => setActiveDay(dayNum)}
              className={`
                flex-shrink-0 flex lg:flex-row flex-col items-center gap-3 lg:gap-4 p-4 lg:px-6 lg:py-4 rounded-2xl transition-all duration-300
                ${isActive 
                  ? 'bg-gradient-to-r from-[#BC002D] to-[#E63946] text-white shadow-lg scale-105' 
                  : 'bg-white text-gray-400 hover:bg-gray-50 border border-gray-100 shadow-sm'}
              `}
            >
              <div className={`text-xl font-black ${isActive ? 'text-white' : 'text-gray-300'}`}>
                {String(dayNum).padStart(2, '0')}
              </div>
              <div className="text-left">
                <p className={`text-[10px] font-black uppercase tracking-widest mb-0.5 ${isActive ? 'text-white/80' : 'text-gray-400'}`}>
                  DAY
                </p>
                <div className="flex items-center gap-2">
                  <WeatherIcon condition={dayData?.weather?.condition || 'Sunny'} isActive={isActive} />
                  <span className={`text-[11px] font-bold ${isActive ? 'text-white/90' : 'text-gray-500'}`}>
                    {dayData?.weather ? `${dayData.weather.tempMin}° / ${dayData.weather.tempMax}°` : '-- / --'}
                  </span>
                </div>
              </div>
            </button>
          );
        })}
      </aside>

      {/* Vertical Timeline */}
      <section className="flex-1 space-y-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-3xl font-black text-[#2D3436] tracking-tight">行程規劃</h2>
            <p className="text-gray-500 font-bold">DAY {activeDay} • {currentItinerary.date}</p>
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-[#2D3436] text-white px-6 py-3.5 rounded-2xl font-bold flex items-center gap-2 shadow-lg hover:bg-black transition-all active:scale-95"
          >
