        <div className="relative">
          <div className="absolute left-[31px] top-6 bottom-6 w-[2px] bg-gray-100 z-0" />

          {currentItinerary.activities.length === 0 ? (
            <div className="bg-white rounded-[2rem] p-16 border-2 border-dashed border-gray-100 text-center flex flex-col items-center gap-4">
              <div className="p-5 bg-gray-50 rounded-full">
                <MapPin className="text-gray-200" size={40} />
