import React from 'react';
import { useParams } from 'react-router-dom';
import { useTrips } from '../store/TripContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Utensils, Camera, TrainFront, Hotel, ShoppingBag, Box, AlertCircle } from 'lucide-react';
import { ActivityType } from '../types';
import { motion } from 'framer-motion';

const COLORS = ['#F97316', '#3B82F6', '#22C55E', '#A855F7', '#EC4899', '#94A3B8'];

const BudgetPage: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  if (!trip) return <div>Trip not found</div>;

  const categorySpending = trip.dailyItinerary.reduce((acc, day) => {
    day.activities.forEach(act => {
      acc[act.type] = (acc[act.type] || 0) + act.cost;
    });
    return acc;
  }, {} as Record<string, number>);

  const data = Object.entries(categorySpending).map(([name, value]) => ({ name, value }));
  const totalSpent = Object.values(categorySpending).reduce((a, b) => a + b, 0);
  const remaining = trip.budget.total - totalSpent;
  const isOverBudget = remaining < 0;

  const categoryIcons: Record<string, any> = {
    [ActivityType.FOOD]: { icon: <Utensils size={18} />, color: 'bg-orange-500' },
    [ActivityType.SIGHTSEEING]: { icon: <Camera size={18} />, color: 'bg-blue-500' },
    [ActivityType.TRANSPORT]: { icon: <TrainFront size={18} />, color: 'bg-green-500' },
    [ActivityType.HOTEL]: { icon: <Hotel size={18} />, color: 'bg-purple-500' },
    [ActivityType.SHOPPING]: { icon: <ShoppingBag size={18} />, color: 'bg-pink-500' },
    'Other': { icon: <Box size={18} />, color: 'bg-slate-400' }
  };

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預算追蹤</h1>
        <p className="text-gray-500 font-medium">掌控你的旅程每一分開支 💰</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Summary Cards */}
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col justify-between">
            <span className="text-xs font-black text-gray-400 uppercase tracking-widest mb-4 block">總預算額度</span>
            <div className="flex items-end gap-3">
              <span className="text-4xl font-black text-[#2D3436]">¥ {trip.budget.total.toLocaleString()}</span>
              <button 
                onClick={() => {
                  const newBudget = prompt('請輸入新的總預算:', trip.budget.total.toString());
                  if (newBudget) updateTrip({...trip, budget: {...trip.budget, total: parseInt(newBudget) || 0}});
                }}
                className="text-xs text-[#BC002D] font-black hover:underline mb-1.5 p-1 px-2 bg-[#BC002D]/5 rounded-lg"
              >
                變更
              </button>
            </div>
          </div>

          <div className={`p-8 rounded-[2.5rem] border shadow-sm flex flex-col justify-between transition-colors duration-500 ${isOverBudget ? 'bg-[#BC002D] border-[#BC002D] shadow-[#BC002D]/20' : 'bg-white border-gray-100'}`}>
            <span className={`text-xs font-black uppercase tracking-widest mb-4 block ${isOverBudget ? 'text-white/70' : 'text-gray-400'}`}>
              {isOverBudget ? '超額支出警告' : '目前剩餘金額'}
            </span>
            <div className="flex items-center justify-between">
              <span className={`text-4xl font-black ${isOverBudget ? 'text-white' : 'text-[#00A86B]'}`}>
                ¥ {Math.abs(remaining).toLocaleString()}
              </span>
              {isOverBudget ? <AlertCircle className="text-white" size={32} /> : <div className="p-2 bg-[#00A86B]/10 rounded-full"><Box className="text-[#00A86B]" size={24} /></div>}
            </div>
          </div>

          {/* Categories */}
          <div className="md:col-span-2 bg-white p-10 rounded-[2.5rem] border border-gray-100 shadow-sm">
            <h3 className="text-xl font-black mb-8 text-[#2D3436] tracking-tight">支出細目分類</h3>
            <div className="space-y-8">
              {Object.keys(ActivityType).map((key, i) => {
                const type = ActivityType[key as keyof typeof ActivityType];
                const amount = categorySpending[type] || 0;
                const percentage = totalSpent > 0 ? (amount / totalSpent) * 100 : 0;
                const info = categoryIcons[type];

                return (
                  <div key={type} className="flex items-center gap-6 group">
                    <div className={`${info.color} text-white p-4 rounded-[1.25rem] shadow-lg group-hover:scale-110 transition-transform`}>
                      {info.icon}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between mb-2 items-end">
                        <span className="font-bold text-[#2D3436] tracking-tight">{type}</span>
                        <div className="text-right">
                          <span className="font-black text-[#2D3436] mr-2">¥ {amount.toLocaleString()}</span>
                          <span className="text-xs font-bold text-gray-400">({percentage.toFixed(0)}%)</span>
                        </div>
                      </div>
                      <div className="h-2.5 w-full bg-gray-50 rounded-full overflow-hidden">
                        <motion.div 
                          initial={{ width: 0 }}
                          animate={{ width: `${percentage}%` }}
                          transition={{ duration: 1, ease: "easeOut" }}
                          className={`h-full ${info.color} rounded-full`}
                        />
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white p-10 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col items-center justify-center min-h-[500px]">
          <h3 className="text-xl font-black mb-2 text-[#2D3436] tracking-tight">消費圓餅圖</h3>
          <p className="text-sm font-bold text-gray-400 mb-10">視覺化你的預算佔比</p>
          <div className="w-full h-[280px] relative">
            {totalSpent > 0 ? (
              <>
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={data}
                      innerRadius={80}
                      outerRadius={105}
                      paddingAngle={6}
                      dataKey="value"
                      stroke="none"
                    >
                      {data.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip 
                      contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px -10px rgba(0,0,0,0.1)', fontWeight: 'bold' }}
                    />
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">已花費</span>
                  <span className="text-2xl font-black text-[#BC002D]">¥{totalSpent.toLocaleString()}</span>
                </div>
              </>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-gray-200 gap-4">
                <div className="w-44 h-44 rounded-full border-[10px] border-gray-50 flex items-center justify-center">
                  <span className="text-xs font-black text-gray-300 uppercase tracking-widest">暫無數據</span>
                </div>
              </div>
            )}
          </div>
          <div className="mt-12 grid grid-cols-2 gap-4 w-full">
            {data.slice(0, 4).map((entry, i) => (
              <div key={entry.name} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                <span className="text-xs font-bold text-gray-500 truncate">{entry.name}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BudgetPage;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  CheckCircle2, Circle, Plus, Trash2, 
  RefreshCcw, ArrowRightLeft, DollarSign, Info
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { motion } from 'framer-motion';

const Toolbox: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [newItem, setNewItem] = useState('');
  const [jpyAmount, setJpyAmount] = useState('1000');
  const [hkdAmount, setHkdAmount] = useState('55');
  const exchangeRate = 0.051; // Hardcoded mock rate

  useEffect(() => {
    const jpy = parseFloat(jpyAmount);
    if (!isNaN(jpy)) {
      setHkdAmount((jpy * exchangeRate).toFixed(2));
    }
  }, [jpyAmount]);

  if (!trip) return <div>Trip not found</div>;

  const toggleCheck = (id: string) => {
    const updated = trip.checklist.map(item => 
      item.id === id ? { ...item, completed: !item.completed } : item
    );
    updateTrip({ ...trip, checklist: updated });
  };

  const deleteItem = (id: string) => {
    const updated = trip.checklist.filter(item => item.id !== id);
    updateTrip({ ...trip, checklist: updated });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    const item = { id: Math.random().toString(36).substr(2, 9), item: newItem, completed: false };
    updateTrip({ ...trip, checklist: [...trip.checklist, item] });
    setNewItem('');
  };

  const completedCount = trip.checklist.filter(i => i.completed).length;
  const progress = trip.checklist.length > 0 ? (completedCount / trip.checklist.length) * 100 : 0;

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">旅行工具箱</h1>
        <p className="text-gray-500 font-medium">完善你的行前準備與資金換算 🧳</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        {/* Checklist */}
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-2xl font-black text-[#2D3436] tracking-tight">行前必備清單</h3>
            <span className="text-xs font-black bg-[#FFB7C5]/30 text-[#BC002D] px-4 py-1.5 rounded-full uppercase tracking-widest">
              {completedCount} / {trip.checklist.length} 完成
            </span>
          </div>

          <div className="mb-10">
            <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">
              <span>準備進度比例</span>
              <span className="text-[#BC002D]">{progress.toFixed(0)}%</span>
            </div>
            <div className="h-2.5 w-full bg-gray-50 rounded-full overflow-hidden shadow-inner">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                className="h-full bg-gradient-to-r from-[#BC002D] to-[#FFB7C5] rounded-full"
              />
            </div>
          </div>

          <form onSubmit={addItem} className="flex gap-3 mb-10">
            <input 
              className="flex-1 px-6 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none focus:ring-4 focus:ring-[#BC002D]/5 focus:bg-white border-2 border-transparent focus:border-[#BC002D]/10 transition-all placeholder:text-gray-300"
              placeholder="新增自訂項目..."
              value={newItem}
              onChange={e => setNewItem(e.target.value)}
            />
            <button className="p-4 bg-[#2D3436] text-white rounded-2xl hover:bg-black transition-all shadow-lg active:scale-95">
              <Plus size={24} />
            </button>
          </form>

          <div className="space-y-3 max-h-[450px] overflow-y-auto pr-2 custom-scrollbar flex-1">
            {trip.checklist.map(item => (
              <div key={item.id} className="group flex items-center justify-between p-4 rounded-2xl hover:bg-gray-50 transition-all border border-transparent hover:border-gray-100">
                <button 
                  onClick={() => toggleCheck(item.id)}
                  className="flex items-center gap-4 flex-1 text-left"
                >
                  {item.completed ? (
                    <div className="p-1 bg-[#00A86B]/10 rounded-full"><CheckCircle2 className="text-[#00A86B]" size={24} /></div>
                  ) : (
                    <Circle className="text-gray-200" size={24} />
                  )}
                  <span className={`font-bold transition-all ${item.completed ? 'text-gray-300 line-through' : 'text-[#2D3436]'}`}>
                    {item.item}
                  </span>
                </button>
                <button 
                  onClick={() => deleteItem(item.id)}
                  className="p-2 text-gray-200 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all hover:bg-red-50 rounded-xl"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            ))}
            {trip.checklist.length === 0 && (
              <div className="py-20 text-center flex flex-col items-center gap-4">
                <div className="p-4 bg-gray-50 rounded-full"><Plus className="text-gray-200" size={32} /></div>
                <p className="text-gray-400 font-bold">清單空空如也，建議從護照開始！</p>
              </div>
            )}
          </div>
        </div>

        {/* Currency Converter */}
        <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col">
          <div className="flex items-center justify-between mb-10">
            <h3 className="text-2xl font-black text-[#2D3436] tracking-tight">匯率實時換算</h3>
            <div className="flex items-center gap-2">
              <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Auto Update</span>
              <RefreshCcw size={18} className="text-[#BC002D] animate-spin-slow cursor-pointer opacity-50 hover:opacity-100" />
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center space-y-12 pb-10">
            <div className="space-y-6">
              <div className="relative group">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-4">日圓 (JPY) - 輸入金額</label>
                <div className="flex items-center bg-gray-50 rounded-[2.5rem] px-8 py-7 group-focus-within:bg-white group-focus-within:ring-4 group-focus-within:ring-[#BC002D]/5 border-2 border-transparent group-focus-within:border-[#BC002D]/10 transition-all">
                  <span className="text-3xl font-black text-[#BC002D] mr-5">¥</span>
                  <input 
                    type="number"
                    className="flex-1 bg-transparent text-4xl font-black text-[#2D3436] outline-none placeholder:text-gray-200"
                    placeholder="0"
                    value={jpyAmount}
                    onChange={e => setJpyAmount(e.target.value)}
                  />
                </div>
              </div>

              <div className="flex justify-center -my-8 relative z-10">
                <div className="bg-[#2D3436] text-white p-5 rounded-full shadow-2xl shadow-gray-300 border-[6px] border-white active:scale-90 transition-transform cursor-pointer">
                  <ArrowRightLeft size={28} />
                </div>
              </div>

              <div className="relative group">
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3 ml-4">港幣 (HKD) - 換算結果</label>
                <div className="flex items-center bg-gray-50 rounded-[2.5rem] px-8 py-7 border-2 border-transparent">
                  <span className="text-3xl font-black text-gray-300 mr-5">$</span>
                  <input 
                    readOnly
                    className="flex-1 bg-transparent text-4xl font-black text-[#00A86B] outline-none"
                    value={hkdAmount}
                  />
                </div>
              </div>
            </div>

            <div className="bg-gray-50 p-6 rounded-[2rem] border border-gray-100 flex items-start gap-4">
              <div className="p-2 bg-white rounded-xl shadow-sm"><Info className="text-[#BC002D]" size={20} /></div>
              <div className="text-xs font-medium text-gray-500 leading-relaxed">
                <span className="block font-black text-[#2D3436] mb-1">今日參考匯率</span>
                當前市場參考匯率：<span className="font-black text-[#BC002D]">1 JPY ≈ {exchangeRate} HKD</span>。數據僅供規劃參考，交易請以即時匯率為準。
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

