};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [errors, setErrors] = useState<{ location?: string; cost?: string }>({});
  const [newActivity, setNewActivity] = useState<Partial<Activity>>({
    time: '10:00',
    type: ActivityType.SIGHTSEEING,
    location: '',
    note: '',
    cost: 0
  });

  if (!trip) return <div>Trip not found</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const validate = () => {
    const newErrors: { location?: string; cost?: string } = {};
    if (!newActivity.location || newActivity.location.trim() === '') {
      newErrors.location = '景點名稱不能為空白';
    }
    if (newActivity.cost !== undefined && newActivity.cost < 0) {
      newErrors.cost = '預計花費不能小於 0';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const addActivity = () => {
    if (!validate()) return;

    const activity: Activity = {
      id: Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...trip.dailyItinerary];
    const index = updatedItinerary.findIndex(i => i.day === activeDay);

    if (index > -1) {
      updatedItinerary[index] = {
        ...updatedItinerary[index],
        activities: [...updatedItinerary[index].activities, activity].sort((a, b) => a.time.localeCompare(b.time))
      };
    } else {
      updatedItinerary.push({
        ...currentItinerary,
        activities: [activity]
      });
    }

    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: trip.budget.spent + activity.cost }
    });
    setErrors({});
    setIsModalOpen(false);
  };

  const deleteActivity = (activityId: string) => {
    const updatedItinerary = trip.dailyItinerary.map(day => {
      if (day.day === activeDay) {
        return {
          ...day,
          activities: day.activities.filter(a => a.id !== activityId)
        };
      }
      return day;
    });

    const activityToDelete = currentItinerary.activities.find(a => a.id === activityId);
    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: Math.max(0, trip.budget.spent - (activityToDelete?.cost || 0)) }
    });
  };

  // Determine how many days to show (max 7 or actual trip length)
  const totalDays = Math.ceil((new Date(trip.endDate).getTime() - new Date(trip.startDate).getTime()) / 86400000) + 1;
  const dayButtons = Array.from({ length: totalDays }, (_, i) => i + 1);

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      {/* Day Selector Sidebar - Improved layout to remove scroll and auto-adjust */}
      <aside className="lg:w-72 grid grid-cols-4 sm:grid-cols-5 md:grid-cols-7 lg:flex lg:flex-col gap-2">
        {dayButtons.map(dayNum => {
          const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
          const isActive = activeDay === dayNum;

          return (
            <button
              key={dayNum}
              onClick={() => setActiveDay(dayNum)}
              className={`
                flex flex-col lg:flex-row items-center justify-center lg:justify-start gap-1 lg:gap-4 p-2 lg:px-6 lg:py-4 rounded-2xl transition-all duration-300
                ${isActive 
                  ? 'bg-gradient-to-r from-[#BC002D] to-[#E63946] text-white shadow-lg scale-105 z-10' 
                  : 'bg-white text-gray-400 hover:bg-gray-50 border border-gray-100 shadow-sm'}
              `}
            >
              <div className={`text-sm lg:text-xl font-black leading-none ${isActive ? 'text-white' : 'text-gray-300'}`}>
                {String(dayNum).padStart(2, '0')}
              </div>
              <div className="text-center lg:text-left">
                <p className={`hidden lg:block text-[10px] font-black uppercase tracking-widest mb-0.5 ${isActive ? 'text-white/80' : 'text-gray-400'}`}>
                  DAY
                </p>
                <div className="flex items-center justify-center lg:justify-start gap-1">
                  <WeatherIcon condition={dayData?.weather?.condition || 'Sunny'} isActive={isActive} />
                  <span className={`hidden lg:inline text-[11px] font-bold ${isActive ? 'text-white/90' : 'text-gray-500'}`}>
                    {dayData?.weather ? `${dayData.weather.tempMin}°/${dayData.weather.tempMax}°` : '--/--'}
                  </span>
                </div>
              </div>
            </button>
          );
        })}
      </aside>

      {/* Vertical Timeline */}
      <section className="flex-1 space-y-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-3xl font-black text-[#2D3436] tracking-tight">行程規劃</h2>
            <p className="text-gray-500 font-bold">DAY {activeDay} • {currentItinerary.date}</p>
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-[#2D3436] text-white px-6 py-3.5 rounded-2xl font-bold flex items-center gap-2 shadow-lg hover:bg-black transition-all active:scale-95"
          >
            <Plus size={20} /> 新增活動
          </button>
        </div>

        <div className="relative">
          <div className="absolute left-[31px] top-6 bottom-6 w-[2px] bg-gray-100 z-0" />

          {currentItinerary.activities.length === 0 ? (
            <div className="flex flex-col gap-4">
               <button 
                onClick={() => setIsModalOpen(true)}
                className="group w-full h-40 rounded-[2rem] border-2 border-dashed border-gray-200 hover:border-[#BC002D] hover:bg-[#BC002D]/5 flex flex-col items-center justify-center gap-4 transition-all duration-300"
              >
                <div className="p-3 bg-gray-50 group-hover:bg-[#BC002D]/10 rounded-full text-gray-400 group-hover:text-[#BC002D] transition-colors shadow-inner">
                  <Plus size={24} />
                </div>
                <span className="text-gray-400 font-bold group-hover:text-[#BC002D]">立即加入第一個景點</span>
              </button>
            </div>
          ) : (
            <div className="space-y-6">
              {currentItinerary.activities.map((activity, idx) => (
                <motion.div 
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.05 }}
                  key={activity.id} 
                  className="relative pl-16 group"
                >
                  <div className="absolute left-[24px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full bg-white border-4 border-[#BC002D] shadow-[0_0_0_4px_white] z-10" />

                  <div className="bg-white p-6 rounded-[1.5rem] shadow-sm border border-gray-50 flex items-center gap-6 group-hover:shadow-md transition-all group-hover:border-[#BC002D]/10">
                    <div className="hidden sm:flex flex-col items-center text-[#2D3436] font-black min-w-[65px] bg-gray-50 py-2 rounded-xl">
                      <Clock size={14} className="mb-1 opacity-40" />
                      <span className="text-sm">{activity.time}</span>
                    </div>

                    <div className="p-4 rounded-2xl bg-gray-50 group-hover:bg-[#BC002D]/5 transition-colors">
                      <TypeIcon type={activity.type} />
                    </div>

                    <div className="flex-1">
                      <div className="flex items-center gap-3">
                        <h4 className="text-lg font-bold text-[#2D3436] tracking-tight">{activity.location}</h4>
                        <span className="text-[10px] px-2.5 py-1 rounded-full bg-gray-100 text-gray-500 uppercase font-black tracking-wider">
                          {activity.type}
                        </span>
                      </div>
                      {activity.note && <p className="text-sm text-gray-400 mt-1 font-medium">{activity.note}</p>}
                    </div>

                    <div className="text-right flex flex-col items-end gap-2">
                      <span className="font-black text-[#BC002D] text-lg">¥{activity.cost.toLocaleString()}</span>
                      <button 
                        onClick={() => deleteActivity(activity.id)}
                        className="p-2 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Add Activity Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0, y: 20 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.9, opacity: 0, y: 20 }}
              className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden"
            >
              <h3 className="text-2xl font-black mb-8 text-[#2D3436] tracking-tight">新增行程活動 ✨</h3>

