                      type="time" 
                      className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none focus:ring-4 focus:ring-[#BC002D]/5 focus:bg-white border-2 border-transparent focus:border-[#BC002D]/10 transition-all"
                      value={newActivity.time}
                      onChange={e => setNewActivity({...newActivity, time: e.target.value})}
                    />
                  </div>
                  <div>
                    <div className="flex justify-between items-center mb-2 ml-1">
                      <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">預計花費 (JPY)</label>
                    </div>
                    <input 
                      type="number" 
                      className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all focus:ring-4 focus:ring-[#BC002D]/5 focus:bg-white ${errors.cost ? 'border-red-500 focus:border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                      placeholder="0"
                      value={newActivity.cost}
                      onChange={e => {
                        const val = parseInt(e.target.value);
                        setNewActivity({...newActivity, cost: isNaN(val) ? 0 : val});
                        if (errors.cost) setErrors({...errors, cost: undefined});
                      }}
                    />
                    {errors.cost && (
                      <div className="flex items-center gap-1 mt-1 ml-1 text-red-500">
                        <AlertCircle size={12} />
                        <span className="text-[10px] font-bold">{errors.cost}</span>
                      </div>
                    )}
                  </div>
                </div>
                <div>
                  <div className="flex justify-between items-center mb-2 ml-1">
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">景點名稱</label>
                  </div>
                  <input 
                    className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all focus:ring-4 focus:ring-[#BC002D]/5 focus:bg-white ${errors.location ? 'border-red-500 focus:border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                    placeholder="輸入地點..."
                    value={newActivity.location}
                    onChange={e => {
                      setNewActivity({...newActivity, location: e.target.value});
                      if (errors.location) setErrors({...errors, location: undefined});
                    }}
                  />
                  {errors.location && (
                    <div className="flex items-center gap-1 mt-1 ml-1 text-red-500">
                      <AlertCircle size={12} />
                      <span className="text-[10px] font-bold">{errors.location}</span>
                    </div>
                  )}
                </div>
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">備註</label>
                  <textarea 
                    className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-medium outline-none focus:ring-4 focus:ring-[#BC002D]/5 focus:bg-white border-2 border-transparent focus:border-[#BC002D]/10 transition-all resize-none h-28"
                    placeholder="有什麼需要注意的嗎？"
                    value={newActivity.note}
                    onChange={e => setNewActivity({...newActivity, note: e.target.value})}
                  />
                </div>
              </div>

              <div className="flex gap-4 mt-10">
                <button 
                  onClick={() => {
                    setIsModalOpen(false);
                    setErrors({});
                  }}
                  className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all"
                >
                  取消
                </button>
                <button 
                  onClick={addActivity}
                  className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:shadow-gray-200 transition-all active:scale-95"
                >
                  儲存行程
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

