                      {dayData.weather.tempMax}°
                    </span>
                  )}
                </div>
              </button>
            );
          })}
        </div>
      </aside>

      {/* Vertical Timeline */}
      <section className="flex-1 space-y-8">
        <div className="flex items-center justify-between mb-8">
