interface TripContextType {
  trips: Trip[];
  addTrip: (trip: Trip) => void;
  updateTrip: (trip: Trip) => void;
  deleteTrip: (id: string) => void;
  getTripById: (id: string) => Trip | undefined;
}

const TripContext = createContext<TripContextType | undefined>(undefined);

const STORAGE_KEY = 'japan_trip_planner_data';

const initialData: Trip[] = [
  {
    id: '1',
    title: '2026 東京之行',
    startDate: '2026-03-25',
    endDate: '2026-04-02',
    status: 'planning',
    coverImage: 'https://picsum.photos/seed/tokyo/800/400',
    dailyItinerary: [
      {
        day: 1,
        date: '2026-03-25',
        weather: { condition: 'CloudSun', tempMin: 12, tempMax: 18 },
        activities: [
          { id: 'a1', time: '10:00', type: 'Sightseeing' as any, location: '淺草寺', cost: 0, note: '雷門拍照' },
          { id: 'a2', time: '12:30', type: 'Food' as any, location: '一蘭拉麵', cost: 1500 }
        ]
      }
    ],
    bookings: [],
    budget: { total: 200000, spent: 1500 },
    checklist: [
      { id: 'c1', item: 'JR Pass', completed: false },
      { id: 'c2', item: '護照', completed: true }
    ]
  }
];

export const TripProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [trips, setTrips] = useState<Trip[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : initialData;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(trips));
  }, [trips]);

  const addTrip = useCallback((trip: Trip) => {
    setTrips(prev => [...prev, trip]);
  }, []);

  const updateTrip = useCallback((updatedTrip: Trip) => {
    setTrips(prev => prev.map(t => t.id === updatedTrip.id ? updatedTrip : t));
  }, []);

  const deleteTrip = useCallback((id: string) => {
    setTrips(prev => prev.filter(t => t.id !== id));
  }, []);

  const getTripById = useCallback((id: string) => {
    const trip = trips.find(t => t.id === id);
    if (trip && !trip.bookings) {
        return { ...trip, bookings: [] };
    }
    return trip;
  }, [trips]);

  return (
    <TripContext.Provider value={{ trips, addTrip, updateTrip, deleteTrip, getTripById }}>
      {children}
    </TripContext.Provider>
  );
};

export const useTrips = () => {
  const context = useContext(TripContext);
  if (!context) throw new Error('useTrips must be used within a TripProvider');
  return context;
};

import React, { useState } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Hash, 
  Trash2, 
  Calendar,
  AlertCircle
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const CategoryIcon = ({ type, contrast = false }: { type: BookingType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case BookingType.FLIGHT: return <Plane size={20} className={contrast ? baseClass : "text-blue-500"} />;
    case BookingType.ACCOMMODATION: return <Hotel size={20} className={contrast ? baseClass : "text-purple-500"} />;
    case BookingType.TICKET: return <Ticket size={20} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <Ticket size={20} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [errors, setErrors] = useState<{ title?: string; date?: string }>({});

  const initialBookingState: Partial<Booking> = {
    type: BookingType.FLIGHT,
    title: '',
    date: '',
    time: '12:00',
    location: '',
    confirmationCode: '',
    note: ''
  };

  const [newBooking, setNewBooking] = useState<Partial<Booking>>(initialBookingState);

  if (!trip) return <div>Trip not found</div>;

  const validate = () => {
    const newErrors: { title?: string; date?: string } = {};
    if (!newBooking.title || newBooking.title.trim() === '') {
      newErrors.title = '名稱不能為空白';
    }
    if (!newBooking.date) {
      newErrors.date = '日期不能為空白';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSaveBooking = () => {
    if (!validate()) return;

    const bookingData: Booking = {
      id: Math.random().toString(36).substr(2, 9),
      type: newBooking.type as BookingType,
      title: newBooking.title || '',
      date: newBooking.date || '',
      time: newBooking.time || '12:00',
      location: newBooking.location || '',
      confirmationCode: newBooking.confirmationCode || '',
      note: newBooking.note || ''
    };

    const updatedBookings = [...(trip.bookings || []), bookingData];
    updateTrip({
      ...trip,
      bookings: updatedBookings
    });

    setNewBooking(initialBookingState);
    setErrors({});
    setIsModalOpen(false);
  };

  const deleteBooking = (id: string) => {
    const updatedBookings = (trip.bookings || []).filter(b => b.id !== id);
    updateTrip({
      ...trip,
      bookings: updatedBookings
    });
  };

  const renderCategory = (type: BookingType, title: string) => {
    const bookings = (trip.bookings || []).filter(b => b.type === type);
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3 mb-6">
          <div className={`p-2 rounded-xl ${
            type === BookingType.FLIGHT ? 'bg-blue-50 text-blue-500' :
            type === BookingType.ACCOMMODATION ? 'bg-purple-50 text-purple-500' :
            'bg-pink-50 text-pink-500'
          }`}>
            <CategoryIcon type={type} />
          </div>
          <h3 className="text-xl font-black text-[#2D3436] tracking-tight">{title}</h3>
          <span className="text-xs font-bold text-gray-400 bg-gray-100 px-2 py-1 rounded-full">{bookings.length}</span>
