  const { tripId } = useParams();
  const { lastTripId, trips } = useTrips();

  // 確定要連結的 Trip ID：優先使用目前頁面的 ID，其次是上次造訪的 ID，最後是列表第一個。
  const effectiveTripId = tripId || lastTripId || (trips.length > 0 ? trips[0].id : null);

  const navItems = [
    { name: '首頁 (Dashboard)', icon: <Home size={20} />, path: '/' },
    { 
      name: '行程規劃 (TripDetail)', 
      icon: <Calendar size={20} />, 
      path: effectiveTripId ? `/trip/${effectiveTripId}` : '#' 
    },
    { 
      name: '預約管理 (Bookings)', 
      icon: <Ticket size={20} />, 
      path: effectiveTripId ? `/bookings/${effectiveTripId}` : '#' 
    },
    { 
      name: '預算追蹤 (Budget)', 
      icon: <Wallet size={20} />, 
      path: effectiveTripId ? `/budget/${effectiveTripId}` : '#' 
    },
    { 
      name: '旅行工具 (Toolbox)', 
      icon: <Briefcase size={20} />, 
      path: effectiveTripId ? `/toolbox/${effectiveTripId}` : '#' 
    },
  ];

  const Sidebar = () => (
    <div className="h-full flex flex-col bg-white border-r border-gray-100 w-64 shadow-sm">
      <div className="p-8 flex items-center gap-3">
        <div className="bg-[#BC002D] p-2 rounded-xl text-white">
          <Plane size={24} />
        </div>
        <span className="text-xl font-bold tracking-tight text-[#2D3436]">日本旅遊</span>
      </div>

      <nav className="flex-1 px-4 py-2 space-y-1">
        {navItems.map((item) => (
          <NavLink
            key={item.name}
            to={item.path}
            onClick={() => {
              if (item.path === '#') alert('請先建立一個旅程規劃！');
              setIsMobileMenuOpen(false);
            }}
            className={({ isActive }) => `
              flex items-center gap-4 px-4 py-3 rounded-2xl transition-all duration-200
              ${isActive && item.path !== '#' 
                ? 'bg-[#BC002D] text-white shadow-md' 
                : 'text-gray-500 hover:bg-gray-50 hover:text-[#BC002D]'}
            `}
          >
            {item.icon}
            <span className="font-medium">{item.name.split(' (')[0]}</span>
          </NavLink>
        ))}
      </nav>

      <div className="p-6">
        <div className="bg-[#FFB7C5]/10 p-4 rounded-3xl border border-[#FFB7C5]/20">
          <p className="text-sm font-semibold text-[#BC002D] mb-1">小貼士 🌸</p>
          <p className="text-xs text-gray-600 leading-relaxed">預約管理可存放機票與住宿確認碼，隨時查看！</p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen">
      <aside className="hidden lg:block fixed h-screen z-20">
        <Sidebar />
      </aside>

      <main className="flex-1 lg:ml-64 bg-[#F8F9FA] min-h-screen">
        <header className="lg:hidden flex items-center justify-between px-6 py-4 glass-effect border-b border-gray-100 sticky top-0 z-30">
          <div className="flex items-center gap-2">
            <Plane size={24} className="text-[#BC002D]" />
            <h1 className="font-bold text-lg text-[#2D3436]">日本旅遊</h1>
          </div>
          <button 
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </header>

        <div className="p-6 md:p-10 max-w-7xl mx-auto">
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.3 }}
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </div>
      </main>

      <AnimatePresence>
        {isMobileMenuOpen && (
          <div className="lg:hidden fixed inset-0 z-40">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setIsMobileMenuOpen(false)}
              className="absolute inset-0 bg-black/40 backdrop-blur-sm"
            />
            <motion.div
              initial={{ x: '-100%' }}
              animate={{ x: 0 }}
              exit={{ x: '-100%' }}
              transition={{ type: 'spring', damping: 25, stiffness: 200 }}
              className="absolute left-0 top-0 bottom-0 w-64 bg-white"
            >
              <Sidebar />
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

