import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Sun, Cloud, CloudSun, CloudRain, CloudSnow, 
  Plus, Utensils, Camera, TrainFront, Hotel, ShoppingBag,
  Clock, MapPin, GripVertical, Trash2, AlertCircle
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, ActivityType, Activity, DailyItinerary } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const TypeIcon = ({ type, contrast = false }: { type: ActivityType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case ActivityType.FOOD: return <Utensils size={18} className={contrast ? baseClass : "text-orange-500"} />;
    case ActivityType.SIGHTSEEING: return <Camera size={18} className={contrast ? baseClass : "text-blue-500"} />;
    case ActivityType.TRANSPORT: return <TrainFront size={18} className={contrast ? baseClass : "text-green-500"} />;
    case ActivityType.HOTEL: return <Hotel size={18} className={contrast ? baseClass : "text-purple-500"} />;
    case ActivityType.SHOPPING: return <ShoppingBag size={18} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <MapPin size={18} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const WeatherIcon = ({ condition, isActive = false }: { condition?: string, isActive?: boolean }) => {
  const baseColor = isActive ? "text-white" : "";
  switch (condition) {
    case 'Sunny': return <Sun size={20} className={isActive ? baseColor : "text-yellow-500"} />;
    case 'Cloudy': return <Cloud size={20} className={isActive ? baseColor : "text-gray-400"} />;
    case 'CloudSun': return <CloudSun size={20} className={isActive ? baseColor : "text-orange-400"} />;
    case 'Rain': return <CloudRain size={20} className={isActive ? baseColor : "text-blue-400"} />;
    case 'Snow': return <CloudSnow size={20} className={isActive ? baseColor : "text-indigo-300"} />;
    default: return <Sun size={20} className={isActive ? baseColor : "text-yellow-500"} />;
  }
};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingActivityId, setEditingActivityId] = useState<string | null>(null);
  const [errors, setErrors] = useState<{ location?: string; cost?: string }>({});

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  const initialActivityState: Partial<Activity> = {
    time: '10:00',
    type: ActivityType.SIGHTSEEING,
    location: '',
    note: '',
    cost: 0
  };

  const [newActivity, setNewActivity] = useState<Partial<Activity>>(initialActivityState);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const validate = () => {
    const newErrors: { location?: string; cost?: string } = {};
    if (!newActivity.location || newActivity.location.trim() === '') {
      newErrors.location = '景點名稱不能為空白';
    }
    if (newActivity.cost !== undefined && newActivity.cost < 0) {
      newErrors.cost = '預計花費不能小於 0';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSaveActivity = () => {
    if (!validate()) return;

    const activityData: Activity = {
      id: editingActivityId || Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...trip.dailyItinerary];
    const dayIndex = updatedItinerary.findIndex(i => i.day === activeDay);

    if (dayIndex > -1) {
      let activities = [...updatedItinerary[dayIndex].activities];
      if (editingActivityId) {
        activities = activities.map(a => a.id === editingActivityId ? activityData : a);
      } else {
        activities.push(activityData);
      }
      updatedItinerary[dayIndex] = {
        ...updatedItinerary[dayIndex],
        activities: activities.sort((a, b) => a.time.localeCompare(b.time))
      };
    } else {
      updatedItinerary.push({
        ...currentItinerary,
        day: activeDay,
        activities: [activityData]
      });
    }

    const newTotalSpent = updatedItinerary.reduce((sum, day) => 
      sum + day.activities.reduce((dSum, act) => dSum + act.cost, 0), 0);

    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: newTotalSpent }
    });

    setNewActivity(initialActivityState);
    setEditingActivityId(null);
    setErrors({});
    setIsModalOpen(false);
  };

  const deleteActivity = (e: React.MouseEvent, activityId: string) => {
    e.stopPropagation();
    const updatedItinerary = trip.dailyItinerary.map(day => {
      if (day.day === activeDay) {
        return {
          ...day,
          activities: day.activities.filter(a => a.id !== activityId)
        };
      }
      return day;
    });

    const newTotalSpent = updatedItinerary.reduce((sum, day) => 
      sum + day.activities.reduce((dSum, act) => dSum + act.cost, 0), 0);

    updateTrip({
      ...trip,
      dailyItinerary: updatedItinerary,
      budget: { ...trip.budget, spent: newTotalSpent }
    });
  };

  const openEditModal = (activity: Activity) => {
    setNewActivity(activity);
    setEditingActivityId(activity.id);
    setIsModalOpen(true);
  };

  const openAddModal = () => {
    setEditingActivityId(null);
    // 不重置 newActivity，保留用戶未儲存的輸入 (符合需求 2)
    setIsModalOpen(true);
  };

  const formatDateLabel = (startDate: string, dayNum: number) => {
    const date = new Date(new Date(startDate).getTime() + (dayNum - 1) * 86400000);
    const dd = String(date.getDate()).padStart(2, '0');
    const mm = String(date.getMonth() + 1).padStart(2, '0');
    return `DAY ${String(dayNum).padStart(2, '0')} (${dd}/${mm})`;
  };

  const totalDays = Math.ceil((new Date(trip.endDate).getTime() - new Date(trip.startDate).getTime()) / 86400000) + 1;
  const dayButtons = Array.from({ length: totalDays }, (_, i) => i + 1);

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      <aside className="lg:w-80 flex flex-col gap-2">
        <div className="grid grid-cols-1 gap-2">
          {dayButtons.map(dayNum => {
            const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
            const isActive = activeDay === dayNum;
            return (
              <button
                key={dayNum}
                onClick={() => setActiveDay(dayNum)}
                className={`
                  flex items-center justify-between px-6 py-4 rounded-2xl transition-all duration-300 group
                  ${isActive 
                    ? 'bg-gradient-to-r from-[#BC002D] to-[#E63946] text-white shadow-lg scale-[1.02] z-10' 
                    : 'bg-white text-gray-500 hover:bg-gray-50 border border-gray-100 shadow-sm'}
                `}
              >
                <span className={`text-sm font-black tracking-tighter ${isActive ? 'text-white' : 'text-[#2D3436]'}`}>
                  {formatDateLabel(trip.startDate, dayNum)}
                </span>
                <div className="flex items-center gap-2">
                  <WeatherIcon condition={dayData?.weather?.condition || 'Sunny'} isActive={isActive} />
                  {dayData?.weather && <span className={`text-[11px] font-bold ${isActive ? 'text-white/80' : 'text-gray-400'}`}>{dayData.weather.tempMax}°</span>}
                </div>
              </button>
            );
          })}
        </div>
      </aside>

      <section className="flex-1 space-y-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-3xl font-black text-[#2D3436] tracking-tight">行程規劃</h2>
            <p className="text-gray-500 font-bold">DAY {activeDay} • {currentItinerary.date}</p>
          </div>
          <button onClick={openAddModal} className="bg-[#2D3436] text-white px-6 py-3.5 rounded-2xl font-bold flex items-center gap-2 shadow-lg hover:bg-black transition-all active:scale-95">
            <Plus size={20} /> 新增活動
          </button>
        </div>

        <div className="relative">
          <div className="absolute left-[31px] top-6 bottom-6 w-[2px] bg-gray-100 z-0" />
          {currentItinerary.activities.length === 0 ? (
            <button onClick={openAddModal} className="group w-full h-40 rounded-[2rem] border-2 border-dashed border-gray-200 hover:border-[#BC002D] hover:bg-[#BC002D]/5 flex flex-col items-center justify-center gap-4 transition-all duration-300">
              <div className="p-3 bg-gray-50 group-hover:bg-[#BC002D]/10 rounded-full text-gray-400 group-hover:text-[#BC002D] transition-colors shadow-inner"><Plus size={24} /></div>
              <span className="text-gray-400 font-bold group-hover:text-[#BC002D]">立即加入第一個景點</span>
            </button>
          ) : (
            <div className="space-y-6">
              {currentItinerary.activities.map((activity, idx) => (
                <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: idx * 0.05 }} key={activity.id} className="relative pl-16 group cursor-pointer" onClick={() => openEditModal(activity)}>
                  <div className="absolute left-[24px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full bg-white border-4 border-[#BC002D] shadow-[0_0_0_4px_white] z-10" />
                  <div className="bg-white p-6 rounded-[1.5rem] shadow-sm border border-gray-50 flex items-center gap-6 group-hover:shadow-md transition-all group-hover:border-[#BC002D]/10">
                    <div className="hidden sm:flex flex-col items-center text-[#2D3436] font-black min-w-[65px] bg-gray-50 py-2 rounded-xl">
                      <Clock size={14} className="mb-1 opacity-40" /><span className="text-sm">{activity.time}</span>
                    </div>
                    <div className="p-4 rounded-2xl bg-gray-50 group-hover:bg-[#BC002D]/5 transition-colors"><TypeIcon type={activity.type} /></div>
                    <div className="flex-1">
                      <div className="flex items-center gap-3">
                        <h4 className="text-lg font-bold text-[#2D3436] tracking-tight">{activity.location}</h4>
                        <span className="text-[10px] px-2.5 py-1 rounded-full bg-gray-100 text-gray-500 uppercase font-black tracking-wider">{activity.type}</span>
                      </div>
                      {activity.note && <p className="text-sm text-gray-400 mt-1 font-medium line-clamp-1">{activity.note}</p>}
                    </div>
                    <div className="text-right flex flex-col items-end gap-2">
                      <span className="font-black text-[#BC002D] text-lg">¥{activity.cost.toLocaleString()}</span>
                      <button onClick={(e) => deleteActivity(e, activity.id)} className="p-2 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all opacity-0 group-hover:opacity-100"><Trash2 size={18} /></button>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </section>

      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => { setIsModalOpen(false); setErrors({}); }} />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden">
              <h3 className="text-2xl font-black mb-8 text-[#2D3436] tracking-tight">{editingActivityId ? '修改行程活動 ✏️' : '新增行程活動 ✨'}</h3>
              <div className="flex gap-3 mb-10 overflow-x-auto pb-4 scrollbar-hide select-none cursor-grab active:cursor-grabbing">
                {[ActivityType.FOOD, ActivityType.SIGHTSEEING, ActivityType.TRANSPORT, ActivityType.HOTEL, ActivityType.SHOPPING].map(type => (
                  <button key={type} onClick={() => setNewActivity({...newActivity, type})} className={`flex-shrink-0 flex flex-col items-center gap-2 p-4 rounded-2xl min-w-[85px] transition-all ${newActivity.type === type ? 'bg-[#BC002D] text-white shadow-lg scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                    <TypeIcon type={type as ActivityType} contrast={newActivity.type === type} />
                    <span className={`text-[10px] font-black uppercase tracking-widest ${newActivity.type === type ? 'text-white' : 'text-gray-400'}`}>{type}</span>
                  </button>
                ))}
              </div>
              <div className="space-y-6">
                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">時間</label>
                    <input type="time" className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" value={newActivity.time} onChange={e => setNewActivity({...newActivity, time: e.target.value})} />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">預計花費 (JPY)</label>
                    <input type="number" className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.cost ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`} placeholder="0" value={newActivity.cost} onChange={e => setNewActivity({...newActivity, cost: parseInt(e.target.value) || 0})} />
                    {errors.cost && <div className="flex items-center gap-1 mt-1 text-red-500 text-[10px] font-bold"><AlertCircle size={12} /><span>{errors.cost}</span></div>}
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">景點名稱</label>
                  <input className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.location ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`} placeholder="輸入地點..." value={newActivity.location} onChange={e => setNewActivity({...newActivity, location: e.target.value})} />
                  {errors.location && <div className="flex items-center gap-1 mt-1 text-red-500 text-[10px] font-bold"><AlertCircle size={12} /><span>{errors.location}</span></div>}
                </div>
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">備註</label>
                  <textarea className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-medium outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all resize-none h-28" placeholder="有什麼需要注意的嗎？" value={newActivity.note} onChange={e => setNewActivity({...newActivity, note: e.target.value})} />
                </div>
              </div>
              <div className="flex gap-4 mt-10">
                <button onClick={() => { setIsModalOpen(false); setErrors({}); }} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all">取消</button>
                <button onClick={handleSaveActivity} className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:bg-black transition-all active:scale-95">{editingActivityId ? '更新行程' : '儲存行程'}</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

