import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Hash, 
  Trash2, 
  Calendar,
  AlertCircle
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const CategoryIcon = ({ type, contrast = false }: { type: BookingType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case BookingType.FLIGHT: return <Plane size={20} className={contrast ? baseClass : "text-blue-500"} />;
    case BookingType.ACCOMMODATION: return <Hotel size={20} className={contrast ? baseClass : "text-purple-500"} />;
    case BookingType.TICKET: return <Ticket size={20} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <Ticket size={20} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBookingId, setEditingBookingId] = useState<string | null>(null);
  const [errors, setErrors] = useState<{ title?: string; date?: string }>({});

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  const initialBookingState: Partial<Booking> = {
    type: BookingType.FLIGHT,
    title: '',
    date: '',
    time: '12:00',
    location: '',
    confirmationCode: '',
    note: ''
  };

  const [newBooking, setNewBooking] = useState<Partial<Booking>>(initialBookingState);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const validate = () => {
    const newErrors: { title?: string; date?: string } = {};
    if (!newBooking.title || newBooking.title.trim() === '') {
      newErrors.title = '名稱不能為空白';
    }
    if (!newBooking.date) {
      newErrors.date = '日期不能為空白';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSaveBooking = () => {
    if (!validate()) return;

    const bookingData: Booking = {
      id: editingBookingId || Math.random().toString(36).substr(2, 9),
      type: newBooking.type as BookingType,
      title: newBooking.title || '',
      date: newBooking.date || '',
      time: newBooking.time || '12:00',
      location: newBooking.location || '',
      confirmationCode: newBooking.confirmationCode || '',
      note: newBooking.note || ''
    };

    let updatedBookings = [...(trip.bookings || [])];
    if (editingBookingId) {
      updatedBookings = updatedBookings.map(b => b.id === editingBookingId ? bookingData : b);
    } else {
      updatedBookings.push(bookingData);
    }

    updateTrip({
      ...trip,
      bookings: updatedBookings
    });

    // 成功儲存後才重置 (符合需求 2)
    setNewBooking(initialBookingState);
    setEditingBookingId(null);
    setErrors({});
    setIsModalOpen(false);
  };

  const openEditModal = (booking: Booking) => {
    setNewBooking(booking);
    setEditingBookingId(booking.id);
    setIsModalOpen(true);
  };

  const openAddModal = () => {
    setEditingBookingId(null);
    // 不重置，保留未儲存輸入
    setIsModalOpen(true);
  };

  const deleteBooking = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updatedBookings = (trip.bookings || []).filter(b => b.id !== id);
    updateTrip({
      ...trip,
      bookings: updatedBookings
    });
  };

  const renderCategory = (type: BookingType, title: string) => {
    const bookings = (trip.bookings || []).filter(b => b.type === type);
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3 mb-6">
          <div className={`p-2 rounded-xl ${
            type === BookingType.FLIGHT ? 'bg-blue-50 text-blue-500' :
            type === BookingType.ACCOMMODATION ? 'bg-purple-50 text-purple-500' :
            'bg-pink-50 text-pink-500'
          }`}>
            <CategoryIcon type={type} />
          </div>
          <h3 className="text-xl font-black text-[#2D3436] tracking-tight">{title}</h3>
          <span className="text-xs font-bold text-gray-400 bg-gray-100 px-2 py-1 rounded-full">{bookings.length}</span>
        </div>

        {bookings.length === 0 ? (
          <div className="bg-white rounded-3xl p-8 border-2 border-dashed border-gray-100 flex flex-col items-center justify-center text-center">
            <p className="text-gray-400 font-bold text-sm">目前沒有任何{title}</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {bookings.map(booking => (
              <motion.div 
                layout
                key={booking.id}
                onClick={() => openEditModal(booking)}
                className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50 flex flex-col gap-4 group hover:shadow-md transition-all hover:border-[#BC002D]/10 cursor-pointer"
              >
                <div className="flex justify-between items-start">
                  <div>
                    <h4 className="font-black text-[#2D3436] text-lg">{booking.title}</h4>
                    <div className="flex items-center gap-2 text-gray-400 text-xs font-bold mt-1">
                      <Calendar size={12} />
                      <span>{booking.date} • {booking.time}</span>
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteBooking(e, booking.id)}
                    className="p-2 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>

                <div className="space-y-2">
                  {booking.location && (
                    <div className="flex items-center gap-2 text-gray-500 text-sm font-medium">
                      <MapPin size={14} className="text-[#BC002D]/40" />
                      <span>{booking.location}</span>
                    </div>
                  )}
                  {booking.confirmationCode && (
                    <div className="flex items-center gap-2 text-gray-500 text-sm font-medium">
                      <Hash size={14} className="text-[#BC002D]/40" />
                      <span className="bg-gray-50 px-2 py-0.5 rounded-lg text-xs font-black uppercase text-gray-400 tracking-tighter">
                        {booking.confirmationCode}
                      </span>
                    </div>
                  )}
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="space-y-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預約管理</h1>
          <p className="text-gray-500 font-bold">集中管理你的交通、住宿與票券 🎫</p>
        </div>
        <button 
          onClick={openAddModal}
          className="bg-[#2D3436] text-white px-6 py-3.5 rounded-2xl font-bold flex items-center gap-2 shadow-lg hover:bg-black transition-all active:scale-95"
        >
          <Plus size={20} /> 新增預約
        </button>
      </div>

      <div className="space-y-16">
        {renderCategory(BookingType.FLIGHT, "機票預約")}
        {renderCategory(BookingType.ACCOMMODATION, "住宿預訂")}
        {renderCategory(BookingType.TICKET, "票券管理")}
      </div>

      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0, y: 20 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.9, opacity: 0, y: 20 }}
              className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden"
            >
              <h3 className="text-2xl font-black mb-8 text-[#2D3436] tracking-tight">
                {editingBookingId ? '修改預約項目 ✏️' : '新增預約項目 ✨'}
              </h3>

              <div className="flex gap-3 mb-10 overflow-x-auto pb-4 scrollbar-hide select-none cursor-grab active:cursor-grabbing">
                {[BookingType.FLIGHT, BookingType.ACCOMMODATION, BookingType.TICKET].map(type => (
                  <button
                    key={type}
                    onClick={() => setNewBooking({...newBooking, type})}
                    className={`
                      flex-shrink-0 flex flex-col items-center gap-2 p-4 rounded-2xl min-w-[100px] transition-all
                      ${newBooking.type === type 
                        ? 'bg-[#BC002D] text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}
                    `}
                  >
                    <CategoryIcon type={type as BookingType} contrast={newBooking.type === type} />
                    <span className={`text-[10px] font-black uppercase tracking-widest ${newBooking.type === type ? 'text-white' : 'text-gray-400'}`}>
                      {type === BookingType.FLIGHT ? '機票' : type === BookingType.ACCOMMODATION ? '住宿' : '票券'}
                    </span>
                  </button>
                ))}
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">名稱 (航班/酒店/票券名)</label>
                  <input 
                    className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.title ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                    placeholder="例如：NH812 航班 / 東京希爾頓..."
                    value={newBooking.title}
                    onChange={e => setNewBooking({...newBooking, title: e.target.value})}
                  />
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">日期</label>
                    <input 
                      type="date"
                      className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.date ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                      value={newBooking.date}
                      onChange={e => setNewBooking({...newBooking, date: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">時間</label>
                    <input type="time" className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" value={newBooking.time} onChange={e => setNewBooking({...newBooking, time: e.target.value})} />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">地點</label>
                    <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" placeholder="地點..." value={newBooking.location} onChange={e => setNewBooking({...newBooking, location: e.target.value})} />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">確認碼 / PNR</label>
                    <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all uppercase" placeholder="代碼..." value={newBooking.confirmationCode} onChange={e => setNewBooking({...newBooking, confirmationCode: e.target.value})} />
                  </div>
                </div>
              </div>

              <div className="flex gap-4 mt-10">
                <button onClick={() => { setIsModalOpen(false); setErrors({}); }} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all">取消</button>
                <button onClick={handleSaveBooking} className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:bg-black transition-all active:scale-95">{editingBookingId ? '更新預約' : '儲存預約'}</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default BookingManagement;

export enum ActivityType {
  FOOD = 'Food',
  SIGHTSEEING = 'Sightseeing',
  TRANSPORT = 'Transport',
  HOTEL = 'Hotel',
  SHOPPING = 'Shopping'
}

export enum BookingType {
  FLIGHT = 'Flight',
  ACCOMMODATION = 'Accommodation',
  TICKET = 'Ticket'
}

export interface Activity {
  id: string;
  time: string;
  type: ActivityType;
  location: string;
  note?: string;
  cost: number;
}

export interface Booking {
  id: string;
  type: BookingType;
  title: string;
  date: string;
  time: string;
  location: string;
  confirmationCode?: string;
  note?: string;
  airline?: string;
  flightNumber?: string;
  terminal?: string;
}

export interface DailyItinerary {
  day: number;
  date: string;
  weather?: {
    condition: 'Sunny' | 'Cloudy' | 'CloudSun' | 'Rain' | 'Snow';
    tempMin: number;
    tempMax: number;
  };
  activities: Activity[];
}

export interface ChecklistItem {
  id: string;
  item: string;
  completed: boolean;
}

export interface TripBudget {
  total: number;
  spent: number;
}

export interface Trip {
  id: string;
  title: string;
  startDate: string;
  endDate: string;
  status: 'planning' | 'ongoing' | 'completed';
  coverImage: string;
  dailyItinerary: DailyItinerary[];
  bookings: Booking[];
  budget: TripBudget;
  checklist: ChecklistItem[];
}

export interface AppState {
  trips: Trip[];
}

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Hash, 
  Trash2, 
  Calendar,
  AlertCircle,
  Loader2,
  PlaneTakeoff,
  PlaneLanding
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const AVIATIONSTACK_KEY = '80ef4fff11c18e7940e85f8947821ab9';

const CategoryIcon = ({ type, contrast = false }: { type: BookingType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case BookingType.FLIGHT: return <Plane size={20} className={contrast ? baseClass : "text-blue-500"} />;
    case BookingType.ACCOMMODATION: return <Hotel size={20} className={contrast ? baseClass : "text-purple-500"} />;
    case BookingType.TICKET: return <Ticket size={20} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <Ticket size={20} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBookingId, setEditingBookingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [errors, setErrors] = useState<{ title?: string; date?: string; flight?: string }>({});

  // 航班專用欄位
  const [flightInfo, setFlightInfo] = useState({
    outboundNo: '',
    outboundDate: '',
    returnNo: '',
    returnDate: ''
  });

  const initialBookingState: Partial<Booking> = {
    type: BookingType.FLIGHT,
    title: '',
    date: '',
    time: '12:00',
    location: '',
    confirmationCode: '',
    note: '',
    airline: '',
    terminal: ''
  };

  const [newBooking, setNewBooking] = useState<Partial<Booking>>(initialBookingState);

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const fetchFlightData = async (flightNo: string) => {
    try {
      // 由於 Aviationstack 免費版可能不支持 HTTPS 查詢特定 IATA 歷史數據，此處實作標準 API 請求流程
      const response = await fetch(`http://api.aviationstack.com/v1/flights?access_key=${AVIATIONSTACK_KEY}&flight_iata=${flightNo.toUpperCase()}`);
      const result = await response.json();

      if (result.data && result.data.length > 0) {
        const flight = result.data[0];
        return {
          airline: flight.airline.name,
          departureTime: flight.departure.scheduled?.split('T')[1]?.substring(0, 5) || '12:00',
          location: `${flight.departure.airport} (${flight.departure.iata})`,
          terminal: flight.departure.terminal || 'T1'
        };
      }
      return null;
    } catch (e) {
      console.error('Flight API error:', e);
      return null;
    }
  };

  const validate = () => {
    const newErrors: any = {};
    if (newBooking.type === BookingType.FLIGHT) {
      if (!flightInfo.outboundNo && !flightInfo.returnNo) newErrors.flight = '請至少輸入一組航班編號';
    } else {
      if (!newBooking.title || newBooking.title.trim() === '') newErrors.title = '名稱不能為空白';
      if (!newBooking.date) newErrors.date = '日期不能為空白';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSaveBooking = async () => {
    if (!validate()) return;
    setIsLoading(true);

    let updatedBookings = [...(trip.bookings || [])];

    if (newBooking.type === BookingType.FLIGHT) {
      // 處理航班：可能包含去程與回程
      const flightsToProcess = [];
      if (flightInfo.outboundNo) flightsToProcess.push({ no: flightInfo.outboundNo, date: flightInfo.outboundDate, label: '去程' });
      if (flightInfo.returnNo) flightsToProcess.push({ no: flightInfo.returnNo, date: flightInfo.returnDate, label: '回程' });

      for (const f of flightsToProcess) {
        const apiData = await fetchFlightData(f.no);
        const bookingData: Booking = {
          id: Math.random().toString(36).substr(2, 9),
          type: BookingType.FLIGHT,
          title: `${f.label}: ${f.no} (${apiData?.airline || '未知航空公司'})`,
          date: f.date || trip.startDate,
          time: apiData?.departureTime || '12:00',
          location: apiData?.location || '待確認機場',
          terminal: apiData?.terminal || '-',
          airline: apiData?.airline || '',
          flightNumber: f.no.toUpperCase(),
          confirmationCode: newBooking.confirmationCode,
          note: newBooking.note
        };
        updatedBookings.push(bookingData);
      }
    } else {
      // 處理住宿或票券
      const bookingData: Booking = {
        id: editingBookingId || Math.random().toString(36).substr(2, 9),
        type: newBooking.type as BookingType,
        title: newBooking.title || '',
        date: newBooking.date || '',
        time: newBooking.time || '12:00',
        location: newBooking.location || '',
        confirmationCode: newBooking.confirmationCode || '',
        note: newBooking.note || ''
      };

      if (editingBookingId) {
        updatedBookings = updatedBookings.map(b => b.id === editingBookingId ? bookingData : b);
      } else {
        updatedBookings.push(bookingData);
      }
    }

    updateTrip({ ...trip, bookings: updatedBookings });
    setIsLoading(false);
    resetForm();
    setIsModalOpen(false);
  };

  const resetForm = () => {
    setNewBooking(initialBookingState);
    setFlightInfo({ outboundNo: '', outboundDate: '', returnNo: '', returnDate: '' });
    setEditingBookingId(null);
    setErrors({});
  };

  const openAddModal = (type: BookingType) => {
    setNewBooking({ ...initialBookingState, type });
    setEditingBookingId(null);
    setIsModalOpen(true);
  };

  const openEditModal = (booking: Booking) => {
    setNewBooking(booking);
    setEditingBookingId(booking.id);
    setIsModalOpen(true);
  };

  const deleteBooking = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updatedBookings = (trip.bookings || []).filter(b => b.id !== id);
    updateTrip({ ...trip, bookings: updatedBookings });
  };

  const renderCategory = (type: BookingType, title: string) => {
    const bookings = (trip.bookings || []).filter(b => b.type === type);
    return (
      <div className="space-y-4">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl ${
              type === BookingType.FLIGHT ? 'bg-blue-50 text-blue-500' :
              type === BookingType.ACCOMMODATION ? 'bg-purple-50 text-purple-500' :
              'bg-pink-50 text-pink-500'
            }`}>
              <CategoryIcon type={type} />
            </div>
            <h3 className="text-xl font-black text-[#2D3436] tracking-tight">{title}</h3>
            <span className="text-xs font-bold text-gray-400 bg-gray-100 px-2 py-1 rounded-full">{bookings.length}</span>
          </div>

          <button 
            onClick={() => openAddModal(type)}
            className="flex items-center gap-2 px-4 py-2 bg-white text-gray-600 border border-gray-100 rounded-xl font-bold text-sm shadow-sm hover:border-[#BC002D] hover:text-[#BC002D] transition-all active:scale-95"
          >
            <Plus size={16} /> 新增
          </button>
        </div>

        {bookings.length === 0 ? (
          <div className="bg-white rounded-3xl p-8 border-2 border-dashed border-gray-100 flex flex-col items-center justify-center text-center">
            <p className="text-gray-400 font-bold text-sm">目前沒有任何{title}</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {bookings.map(booking => (
              <motion.div 
                layout
                key={booking.id}
                onClick={() => openEditModal(booking)}
                className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50 flex flex-col gap-4 group hover:shadow-md transition-all hover:border-[#BC002D]/10 cursor-pointer"
              >
                <div className="flex justify-between items-start">
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      {booking.type === BookingType.FLIGHT && <Plane size={14} className="text-[#BC002D]" />}
                      <h4 className="font-black text-[#2D3436] text-lg leading-tight">{booking.title}</h4>
                    </div>
                    <div className="flex items-center gap-3 text-gray-400 text-xs font-bold mt-2">
                      <div className="flex items-center gap-1">
                        <Calendar size={12} />
                        <span>{booking.date}</span>
                      </div>
                      <div className="flex items-center gap-1">
                        <Clock size={12} />
                        <span>{booking.time}</span>
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={(e) => deleteBooking(e, booking.id)}
                    className="p-2 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>

                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-gray-500 text-sm font-medium">
                    <MapPin size={14} className="text-[#BC002D]/40" />
                    <span className="truncate">{booking.location} {booking.terminal ? `(航站: ${booking.terminal})` : ''}</span>
                  </div>
                  {booking.confirmationCode && (
                    <div className="flex items-center gap-2 text-gray-500 text-sm font-medium">
                      <Hash size={14} className="text-[#BC002D]/40" />
                      <span className="bg-gray-50 px-2 py-0.5 rounded-lg text-xs font-black uppercase text-gray-400 tracking-tighter">
                        {booking.confirmationCode}
                      </span>
                    </div>
                  )}
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="space-y-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預約管理</h1>
          <p className="text-gray-500 font-bold">集中管理你的交通、住宿與票券 🎫</p>
        </div>
      </div>

      <div className="space-y-16">
        {renderCategory(BookingType.FLIGHT, "機票預約")}
        {renderCategory(BookingType.ACCOMMODATION, "住宿預訂")}
        {renderCategory(BookingType.TICKET, "票券管理")}
      </div>

      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0, y: 20 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.9, opacity: 0, y: 20 }}
              className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden"
            >
              <h3 className="text-2xl font-black mb-8 text-[#2D3436] tracking-tight">
                {editingBookingId ? '修改預約項目 ✏️' : `新增${newBooking.type === BookingType.FLIGHT ? '機票' : newBooking.type === BookingType.ACCOMMODATION ? '住宿' : '票券'} ✨`}
              </h3>

              <div className="space-y-6">
                {newBooking.type === BookingType.FLIGHT ? (
                  // 航班專屬表單
                  <div className="space-y-6">
                    <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100/50 space-y-4">
                      <div className="flex items-center gap-2 text-blue-600 font-black text-xs uppercase tracking-widest">
                        <PlaneTakeoff size={14} /> 去程航班
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <input 
                          className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-blue-200 transition-all uppercase"
                          placeholder="航班編號 (例: NH812)"
                          value={flightInfo.outboundNo}
                          onChange={e => setFlightInfo({...flightInfo, outboundNo: e.target.value})}
                        />
                        <input 
                          type="date"
                          className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-blue-200 transition-all"
                          value={flightInfo.outboundDate}
                          onChange={e => setFlightInfo({...flightInfo, outboundDate: e.target.value})}
                        />
                      </div>
                    </div>

                    <div className="p-6 bg-pink-50/50 rounded-3xl border border-pink-100/50 space-y-4">
                      <div className="flex items-center gap-2 text-pink-600 font-black text-xs uppercase tracking-widest">
                        <PlaneLanding size={14} /> 回程航班
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <input 
                          className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-pink-200 transition-all uppercase"
                          placeholder="航班編號 (例: NH811)"
                          value={flightInfo.returnNo}
                          onChange={e => setFlightInfo({...flightInfo, returnNo: e.target.value})}
                        />
                        <input 
                          type="date"
                          className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-pink-200 transition-all"
                          value={flightInfo.returnDate}
                          onChange={e => setFlightInfo({...flightInfo, returnDate: e.target.value})}
                        />
                      </div>
                    </div>
                    {errors.flight && <div className="text-red-500 text-xs font-bold ml-2">{errors.flight}</div>}
                  </div>
                ) : (
                  // 一般表單
                  <>
                    <div>
                      <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">名稱 (酒店/票券名)</label>
                      <input 
                        className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.title ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                        placeholder="例如：東京希爾頓 / JR Pass..."
                        value={newBooking.title}
                        onChange={e => setNewBooking({...newBooking, title: e.target.value})}
                      />
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                      <div>
                        <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">日期</label>
                        <input 
                          type="date"
                          className={`w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 transition-all ${errors.date ? 'border-red-500' : 'border-transparent focus:border-[#BC002D]/10'}`}
                          value={newBooking.date}
                          onChange={e => setNewBooking({...newBooking, date: e.target.value})}
                        />
                      </div>
                      <div>
                        <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">時間</label>
                        <input type="time" className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" value={newBooking.time} onChange={e => setNewBooking({...newBooking, time: e.target.value})} />
                      </div>
                    </div>

                    <div>
                      <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">地點</label>
                      <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" placeholder="輸入詳細地址或地點..." value={newBooking.location} onChange={e => setNewBooking({...newBooking, location: e.target.value})} />
                    </div>
                  </>
                )}

                <div className="grid grid-cols-1 gap-4">
                  <div>
                    <label className="block text-xs font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">確認碼 / 備註</label>
                    <div className="grid grid-cols-2 gap-4">
                      <input className="px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all uppercase" placeholder="確認碼..." value={newBooking.confirmationCode} onChange={e => setNewBooking({...newBooking, confirmationCode: e.target.value})} />
                      <input className="px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/10 transition-all" placeholder="額外備註..." value={newBooking.note} onChange={e => setNewBooking({...newBooking, note: e.target.value})} />
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex gap-4 mt-10">
                <button onClick={() => { setIsModalOpen(false); resetForm(); }} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all">取消</button>
                <button 
                  onClick={handleSaveBooking} 
                  disabled={isLoading}
                  className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  {isLoading ? (
                    <><Loader2 size={18} className="animate-spin" /> 查詢航班中...</>
                  ) : (
                    editingBookingId ? '更新預約' : '儲存預約'
                  )}
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default BookingManagement;

export enum ActivityType {
  FOOD = 'Food',
  SIGHTSEEING = 'Sightseeing',
  TRANSPORT = 'Transport',
  HOTEL = 'Hotel',
  SHOPPING = 'Shopping'
}

export enum BookingType {
  FLIGHT = 'Flight',
  ACCOMMODATION = 'Accommodation',
  TICKET = 'Ticket'
}

export interface Activity {
  id: string;
  time: string;
  type: ActivityType;
  location: string;
  note?: string;
  cost: number;
}

export interface Booking {
  id: string;
  type: BookingType;
  title: string;
  date: string; // 對機票是出發日，對票券是日期
  time?: string; // 對機票是起飛時間
  location: string;
  confirmationCode?: string;
  note?: string;
  airline?: string;
  flightNumber?: string;
  terminal?: string;
  // 住宿專用
  checkInDate?: string;
  checkOutDate?: string;
}

export interface DailyItinerary {
  day: number;
  date: string;
  weather?: {
    condition: 'Sunny' | 'Cloudy' | 'CloudSun' | 'Rain' | 'Snow';
    tempMin: number;
    tempMax: number;
  };
  activities: Activity[];
}

export interface ChecklistItem {
  id: string;
  item: string;
  completed: boolean;
}

export interface TripBudget {
  total: number;
  spent: number;
}

export interface Trip {
  id: string;
  title: string;
  startDate: string;
  endDate: string;
  status: 'planning' | 'ongoing' | 'completed';
  coverImage: string;
  dailyItinerary: DailyItinerary[];
  bookings: Booking[];
  budget: TripBudget;
  checklist: ChecklistItem[];
}

export interface AppState {
  trips: Trip[];
}

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Hash, 
  Trash2, 
  Calendar,
  AlertCircle,
  Loader2,
  PlaneTakeoff,
  PlaneLanding,
  Map as MapIcon,
  ExternalLink
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI } from "@google/genai";

const CategoryIcon = ({ type, contrast = false }: { type: BookingType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case BookingType.FLIGHT: return <Plane size={20} className={contrast ? baseClass : "text-blue-500"} />;
    case BookingType.ACCOMMODATION: return <Hotel size={20} className={contrast ? baseClass : "text-purple-500"} />;
    case BookingType.TICKET: return <Ticket size={20} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <Ticket size={20} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBookingId, setEditingBookingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [errors, setErrors] = useState<any>({});

  // 航班與住宿專用狀態
  const [flightInfo, setFlightInfo] = useState({
    outboundNo: '', outboundDate: '',
    returnNo: '', returnDate: ''
  });

  const [accInfo, setAccInfo] = useState({
    title: '', checkIn: '', checkOut: '', address: ''
  });

  const [newBooking, setNewBooking] = useState<Partial<Booking>>({ type: BookingType.FLIGHT });

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const searchFlightWithGemini = async (flightNo: string, date: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `請查詢航班編號 ${flightNo} 於 ${date} 的詳情。
      請務必返回以下資訊（JSON格式）：
      {
        "airline": "航空公司名稱(繁體中文)",
        "departureTime": "起飛時間(HH:mm)",
        "airport": "起飛機場名稱",
        "terminal": "航站",
        "status": "航班狀態"
      }
      如果找不到，請盡可能根據該編號提供常規執飛資訊。只回傳 JSON。`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        }
      });

      return JSON.parse(response.text || '{}');
    } catch (e) {
      console.error('Gemini Flight Search Error:', e);
      return null;
    }
  };

  const handleSaveBooking = async () => {
    setErrors({});
    setIsLoading(true);

    let updatedBookings = [...(trip.bookings || [])];

    try {
      if (newBooking.type === BookingType.FLIGHT) {
        if (!flightInfo.outboundNo && !flightInfo.returnNo) {
          setErrors({ flight: '請輸入至少一個航班編號' });
          setIsLoading(false);
          return;
        }

        const flights = [];
        if (flightInfo.outboundNo) flights.push({ no: flightInfo.outboundNo, date: flightInfo.outboundDate || trip.startDate, label: '去程' });
        if (flightInfo.returnNo) flights.push({ no: flightInfo.returnNo, date: flightInfo.returnDate || trip.endDate, label: '回程' });

        for (const f of flights) {
          const info = await searchFlightWithGemini(f.no, f.date);
          updatedBookings.push({
            id: Math.random().toString(36).substr(2, 9),
            type: BookingType.FLIGHT,
            title: `${f.label}: ${f.no}`,
            airline: info?.airline || '未知航空公司',
            date: f.date,
            time: info?.departureTime || '待定',
            location: info?.airport || '待確認機場',
            terminal: info?.terminal || '-',
            flightNumber: f.no.toUpperCase(),
            note: info?.status ? `狀態: ${info.status}` : ''
          });
        }
      } else if (newBooking.type === BookingType.ACCOMMODATION) {
        if (!accInfo.title || !accInfo.checkIn || !accInfo.checkOut) {
          setErrors({ acc: '請完整填寫住宿資訊' });
          setIsLoading(false);
          return;
        }
        updatedBookings.push({
          id: Math.random().toString(36).substr(2, 9),
          type: BookingType.ACCOMMODATION,
          title: accInfo.title,
          checkInDate: accInfo.checkIn,
          checkOutDate: accInfo.checkOut,
          location: accInfo.address || '未提供地址',
          date: accInfo.checkIn // 作為排序基準
        });
      }

      updateTrip({ ...trip, bookings: updatedBookings });
      setIsModalOpen(false);
      resetForms();
    } catch (e) {
      alert('儲存失敗，請重試');
    } finally {
      setIsLoading(false);
    }
  };

  const resetForms = () => {
    setFlightInfo({ outboundNo: '', outboundDate: '', returnNo: '', returnDate: '' });
    setAccInfo({ title: '', checkIn: '', checkOut: '', address: '' });
    setNewBooking({ type: BookingType.FLIGHT });
  };

  const openMaps = (address: string) => {
    const url = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
    window.open(url, '_blank');
  };

  const deleteBooking = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    updateTrip({ ...trip, bookings: (trip.bookings || []).filter(b => b.id !== id) });
  };

  return (
    <div className="space-y-12">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預約管理</h1>
          <p className="text-gray-500 font-bold">由 Google 搜尋驅動的即時行程管理 ✈️</p>
        </div>
      </div>

      <div className="space-y-16">
        {/* 機票預約版面 */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-blue-50 text-blue-500"><Plane size={20} /></div>
              <h3 className="text-xl font-black text-[#2D3436]">機票預約</h3>
            </div>
            <button onClick={() => { setNewBooking({type: BookingType.FLIGHT}); setIsModalOpen(true); }} className="px-4 py-2 bg-white text-blue-600 border border-blue-100 rounded-xl font-bold text-sm hover:bg-blue-50 transition-all flex items-center gap-2 shadow-sm">
              <Plus size={16} /> 新增機票
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {(trip.bookings || []).filter(b => b.type === BookingType.FLIGHT).map(booking => (
              <motion.div layout key={booking.id} className="relative overflow-hidden bg-gradient-to-br from-[#2D3436] to-[#1A1A1A] p-8 rounded-[2rem] shadow-xl text-white group border border-white/5">
                <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity">
                  <Plane size={120} className="-rotate-45" />
                </div>
                <div className="flex justify-between items-start relative z-10">
                  <div className="space-y-1">
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400/80">{booking.airline}</span>
                    <h4 className="text-2xl font-black">{booking.flightNumber}</h4>
                  </div>
                  <button onClick={(e) => deleteBooking(e, booking.id)} className="p-2 text-white/20 hover:text-red-400 transition-colors"><Trash2 size={20} /></button>
                </div>

                <div className="mt-8 flex items-end justify-between relative z-10">
                  <div>
                    <div className="text-[10px] font-bold text-white/40 uppercase tracking-widest mb-1">DEPARTURE TIME 起飛時間</div>
                    <div className="text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">
                      {booking.time}
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-sm font-bold">{booking.date}</div>
                    <div className="text-xs text-white/60">{booking.location}</div>
                  </div>
                </div>
                <div className="mt-4 pt-4 border-t border-white/10 flex justify-between items-center text-[10px] font-bold text-white/40 tracking-widest uppercase">
                  <span>TERMINAL: {booking.terminal}</span>
                  <span>CONFIRMED ✓</span>
                </div>
              </motion.div>
            ))}
          </div>
        </div>

        {/* 住宿預訂版面 */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-purple-50 text-purple-500"><Hotel size={20} /></div>
              <h3 className="text-xl font-black text-[#2D3436]">住宿預訂</h3>
            </div>
            <button onClick={() => { setNewBooking({type: BookingType.ACCOMMODATION}); setIsModalOpen(true); }} className="px-4 py-2 bg-white text-purple-600 border border-purple-100 rounded-xl font-bold text-sm hover:bg-purple-50 transition-all flex items-center gap-2 shadow-sm">
              <Plus size={16} /> 新增住宿
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {(trip.bookings || []).filter(b => b.type === BookingType.ACCOMMODATION).map(booking => (
              <motion.div layout key={booking.id} className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100 hover:shadow-md transition-all group">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h4 className="text-xl font-black text-[#2D3436] mb-1">{booking.title}</h4>
                    <div className="flex items-center gap-2 text-xs font-bold text-[#BC002D]">
                      <Calendar size={14} />
                      <span>{booking.checkInDate} — {booking.checkOutDate}</span>
                    </div>
                  </div>
                  <button onClick={(e) => deleteBooking(e, booking.id)} className="p-2 text-gray-200 hover:text-red-500 rounded-xl"><Trash2 size={18} /></button>
                </div>
                <div className="flex items-start gap-2 mb-6 text-gray-400 text-sm">
                  <MapPin size={16} className="mt-0.5 shrink-0" />
                  <p className="line-clamp-2">{booking.location}</p>
                </div>
                <button 
                  onClick={() => openMaps(booking.location)}
                  className="w-full py-3.5 bg-gray-50 hover:bg-[#BC002D] hover:text-white rounded-2xl text-gray-500 font-black text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2"
                >
                  <MapIcon size={14} /> 在 Google 地圖中查看
                </button>
              </motion.div>
            ))}
          </div>
        </div>
      </div>

      {/* 整合彈窗 */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => !isLoading && setIsModalOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl">
              <h3 className="text-2xl font-black mb-8 text-[#2D3436]">新增{newBooking.type === BookingType.FLIGHT ? '機票' : '住宿'} ✨</h3>

              <div className="space-y-6">
                {newBooking.type === BookingType.FLIGHT ? (
                  <div className="space-y-5">
                    <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100/30 space-y-4">
                      <div className="text-[10px] font-black text-blue-600 uppercase tracking-widest">去程航班</div>
                      <div className="grid grid-cols-2 gap-4">
                        <input className="px-5 py-4 rounded-2xl bg-white font-bold outline-none border-2 border-transparent focus:border-blue-200 uppercase" placeholder="航班編號" value={flightInfo.outboundNo} onChange={e => setFlightInfo({...flightInfo, outboundNo: e.target.value})} />
                        <input type="date" className="px-5 py-4 rounded-2xl bg-white font-bold outline-none border-2 border-transparent focus:border-blue-200" value={flightInfo.outboundDate} onChange={e => setFlightInfo({...flightInfo, outboundDate: e.target.value})} />
                      </div>
                    </div>
                    <div className="p-6 bg-pink-50/50 rounded-3xl border border-pink-100/30 space-y-4">
                      <div className="text-[10px] font-black text-pink-600 uppercase tracking-widest">回程航班 (選填)</div>
                      <div className="grid grid-cols-2 gap-4">
                        <input className="px-5 py-4 rounded-2xl bg-white font-bold outline-none border-2 border-transparent focus:border-pink-200 uppercase" placeholder="航班編號" value={flightInfo.returnNo} onChange={e => setFlightInfo({...flightInfo, returnNo: e.target.value})} />
                        <input type="date" className="px-5 py-4 rounded-2xl bg-white font-bold outline-none border-2 border-transparent focus:border-pink-200" value={flightInfo.returnDate} onChange={e => setFlightInfo({...flightInfo, returnDate: e.target.value})} />
                      </div>
                    </div>
                    {errors.flight && <p className="text-red-500 text-xs font-bold">{errors.flight}</p>}
                  </div>
                ) : (
                  <div className="space-y-5">
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">住宿名稱</label>
                      <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" placeholder="例如：東京希爾頓酒店" value={accInfo.title} onChange={e => setAccInfo({...accInfo, title: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">入住日期</label>
                        <input type="date" className="w-full px-5 py-4 rounded-2xl bg-gray-50 font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" value={accInfo.checkIn} onChange={e => setAccInfo({...accInfo, checkIn: e.target.value})} />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">退房日期</label>
                        <input type="date" className="w-full px-5 py-4 rounded-2xl bg-gray-50 font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" value={accInfo.checkOut} onChange={e => setAccInfo({...accInfo, checkOut: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">住宿地址 (供地圖搜尋)</label>
                      <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" placeholder="輸入詳細地址..." value={accInfo.address} onChange={e => setAccInfo({...accInfo, address: e.target.value})} />
                    </div>
                  </div>
                )}
              </div>

              <div className="flex gap-4 mt-10">
                <button disabled={isLoading} onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all">取消</button>
                <button disabled={isLoading} onClick={handleSaveBooking} className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:bg-black transition-all flex items-center justify-center gap-2">
                  {isLoading ? <><Loader2 size={18} className="animate-spin" /> 正在同步資訊...</> : '確認儲存'}
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default BookingManagement;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Hash, 
  Trash2, 
  Calendar,
  AlertCircle,
  Loader2,
  PlaneTakeoff,
  PlaneLanding,
  Map as MapIcon,
  Search
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI } from "@google/genai";

const CategoryIcon = ({ type, contrast = false }: { type: BookingType, contrast?: boolean }) => {
  const baseClass = contrast ? "text-white" : "";
  switch (type) {
    case BookingType.FLIGHT: return <Plane size={20} className={contrast ? baseClass : "text-blue-500"} />;
    case BookingType.ACCOMMODATION: return <Hotel size={20} className={contrast ? baseClass : "text-purple-500"} />;
    case BookingType.TICKET: return <Ticket size={20} className={contrast ? baseClass : "text-pink-500"} />;
    default: return <Ticket size={20} className={contrast ? baseClass : "text-gray-500"} />;
  }
};

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBookingId, setEditingBookingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [errors, setErrors] = useState<any>({});

  // 航班與住宿專用狀態
  const [flightInfo, setFlightInfo] = useState({
    outboundNo: '', outboundDate: '',
    returnNo: '', returnDate: ''
  });

  const [accInfo, setAccInfo] = useState({
    title: '', checkIn: '', checkOut: '', address: ''
  });

  const [newBooking, setNewBooking] = useState<Partial<Booking>>({ type: BookingType.FLIGHT });

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const searchFlightWithGemini = async (flightNo: string, date: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `請查詢航班編號 ${flightNo} 於 ${date} 的詳情。
      請務必返回以下資訊（JSON格式）：
      {
        "airline": "航空公司名稱(繁體中文)",
        "departureTime": "起飛時間(HH:mm)",
        "airport": "起飛機場名稱",
        "terminal": "航站",
        "status": "航班狀態"
      }
      如果找不到，請盡可能根據該編號提供常規執飛資訊。只回傳 JSON。`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        }
      });

      return JSON.parse(response.text || '{}');
    } catch (e) {
      console.error('Gemini Flight Search Error:', e);
      return null;
    }
  };

  const handleSaveBooking = async () => {
    setErrors({});

    // 驗證邏輯
    if (newBooking.type === BookingType.FLIGHT) {
      if (!editingBookingId && !flightInfo.outboundNo && !flightInfo.returnNo) {
        setErrors({ flight: '請輸入至少一個航班編號' });
        return;
      }
      if (editingBookingId && !flightInfo.outboundNo) {
        setErrors({ flight: '航班編號不能為空' });
        return;
      }
    } else if (newBooking.type === BookingType.ACCOMMODATION) {
      if (!accInfo.title || !accInfo.checkIn || !accInfo.checkOut) {
        setErrors({ acc: '請完整填寫住宿資訊' });
        return;
      }
    }

    // 關閉彈窗並開啟載入狀態
    setIsModalOpen(false);
    setIsLoading(true);

    let updatedBookings = [...(trip.bookings || [])];

    try {
      if (newBooking.type === BookingType.FLIGHT) {
        if (editingBookingId) {
          // 編輯模式：僅處理單一航班
          const info = await searchFlightWithGemini(flightInfo.outboundNo, flightInfo.outboundDate || trip.startDate);
          const editedBooking: Booking = {
            id: editingBookingId,
            type: BookingType.FLIGHT,
            title: `航班: ${flightInfo.outboundNo}`,
            airline: info?.airline || '未知航空公司',
            date: flightInfo.outboundDate || trip.startDate,
            time: info?.departureTime || '待定',
            location: info?.airport || '待確認機場',
            terminal: info?.terminal || '-',
            flightNumber: flightInfo.outboundNo.toUpperCase(),
            note: info?.status ? `狀態: ${info.status}` : ''
          };
          updatedBookings = updatedBookings.map(b => b.id === editingBookingId ? editedBooking : b);
        } else {
          // 新增模式：處理去程與回程
          const flights = [];
          if (flightInfo.outboundNo) flights.push({ no: flightInfo.outboundNo, date: flightInfo.outboundDate || trip.startDate, label: '去程' });
          if (flightInfo.returnNo) flights.push({ no: flightInfo.returnNo, date: flightInfo.returnDate || trip.endDate, label: '回程' });

          for (const f of flights) {
            const info = await searchFlightWithGemini(f.no, f.date);
            updatedBookings.push({
              id: Math.random().toString(36).substr(2, 9),
              type: BookingType.FLIGHT,
              title: `${f.label}: ${f.no}`,
              airline: info?.airline || '未知航空公司',
              date: f.date,
              time: info?.departureTime || '待定',
              location: info?.airport || '待確認機場',
              terminal: info?.terminal || '-',
              flightNumber: f.no.toUpperCase(),
              note: info?.status ? `狀態: ${info.status}` : ''
            });
          }
        }
      } else if (newBooking.type === BookingType.ACCOMMODATION) {
        const bookingData: Booking = {
          id: editingBookingId || Math.random().toString(36).substr(2, 9),
          type: BookingType.ACCOMMODATION,
          title: accInfo.title,
          checkInDate: accInfo.checkIn,
          checkOutDate: accInfo.checkOut,
          location: accInfo.address || '未提供地址',
          date: accInfo.checkIn
        };

        if (editingBookingId) {
          updatedBookings = updatedBookings.map(b => b.id === editingBookingId ? bookingData : b);
        } else {
          updatedBookings.push(bookingData);
        }
      }

      updateTrip({ ...trip, bookings: updatedBookings });
      resetForms();
    } catch (e) {
      alert('同步失敗，資訊可能未完整獲取，請檢查網路連線。');
    } finally {
      setIsLoading(false);
    }
  };

  const resetForms = () => {
    setFlightInfo({ outboundNo: '', outboundDate: '', returnNo: '', returnDate: '' });
    setAccInfo({ title: '', checkIn: '', checkOut: '', address: '' });
    setNewBooking({ type: BookingType.FLIGHT });
    setEditingBookingId(null);
  };

  const openFlightEdit = (booking: Booking) => {
    setEditingBookingId(booking.id);
    setNewBooking({ type: BookingType.FLIGHT });
    setFlightInfo({
      outboundNo: booking.flightNumber || '',
      outboundDate: booking.date || '',
      returnNo: '',
      returnDate: ''
    });
    setIsModalOpen(true);
  };

  const openAccEdit = (booking: Booking) => {
    setEditingBookingId(booking.id);
    setNewBooking({ type: BookingType.ACCOMMODATION });
    setAccInfo({
      title: booking.title || '',
      checkIn: booking.checkInDate || '',
      checkOut: booking.checkOutDate || '',
      address: booking.location || ''
    });
    setIsModalOpen(true);
  };

  const openMaps = (address: string) => {
    const url = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
    window.open(url, '_blank');
  };

  const deleteBooking = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    updateTrip({ ...trip, bookings: (trip.bookings || []).filter(b => b.id !== id) });
  };

  return (
    <div className="space-y-12 relative">
      {/* 載入中遮罩層 */}
      <AnimatePresence>
        {isLoading && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] flex flex-col items-center justify-center bg-white/80 backdrop-blur-md"
          >
            <div className="bg-[#2D3436] p-10 rounded-[3rem] shadow-2xl flex flex-col items-center gap-6">
              <Loader2 size={48} className="text-white animate-spin" />
              <div className="text-center">
                <p className="text-white font-black text-xl tracking-tight">正在同步航班資訊</p>
                <p className="text-gray-400 text-sm mt-2 font-bold uppercase tracking-widest">請稍候片刻...</p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-4xl font-extrabold text-[#2D3436] tracking-tight mb-2">預約管理</h1>
          <p className="text-gray-500 font-bold">由 Google 搜尋驅動的即時行程管理 ✈️</p>
        </div>
      </div>

      <div className="space-y-16">
        {/* 機票預約版面 */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-blue-50 text-blue-500"><Plane size={20} /></div>
              <h3 className="text-xl font-black text-[#2D3436]">機票預約</h3>
            </div>
            <button onClick={() => { resetForms(); setNewBooking({type: BookingType.FLIGHT}); setIsModalOpen(true); }} className="px-4 py-2 bg-white text-blue-600 border border-blue-100 rounded-xl font-bold text-sm hover:bg-blue-50 transition-all flex items-center gap-2 shadow-sm">
              <Plus size={16} /> 新增機票
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {(trip.bookings || []).filter(b => b.type === BookingType.FLIGHT).map(booking => (
              <motion.div 
                layout 
                key={booking.id} 
                onClick={() => openFlightEdit(booking)}
                className="relative overflow-hidden bg-gradient-to-br from-[#2D3436] to-[#1A1A1A] p-8 rounded-[2rem] shadow-xl text-white group border border-white/5 cursor-pointer hover:scale-[1.02] transition-transform"
              >
                <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:opacity-20 transition-opacity">
                  <Plane size={120} className="-rotate-45" />
                </div>
                <div className="flex justify-between items-start relative z-10">
                  <div className="space-y-1">
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400/80">{booking.airline}</span>
                    <h4 className="text-2xl font-black text-white">{booking.flightNumber}</h4>
                  </div>
                  <button onClick={(e) => deleteBooking(e, booking.id)} className="p-2 text-white/20 hover:text-red-400 transition-colors"><Trash2 size={20} /></button>
                </div>

                <div className="mt-8 flex items-end justify-between relative z-10">
                  <div>
                    <div className="text-[10px] font-bold text-white/40 uppercase tracking-widest mb-1">DEPARTURE TIME 起飛時間</div>
                    <div className="text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">
                      {booking.time}
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-sm font-bold text-white">{booking.date}</div>
                    <div className="text-xs text-white/60">{booking.location}</div>
                  </div>
                </div>
                <div className="mt-4 pt-4 border-t border-white/10 flex justify-between items-center text-[10px] font-bold text-white/40 tracking-widest uppercase">
                  <span>TERMINAL: {booking.terminal}</span>
                  <span className="text-blue-400">點擊修改編號 ✓</span>
                </div>
              </motion.div>
            ))}
          </div>
        </div>

        {/* 住宿預訂版面 */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-purple-50 text-purple-500"><Hotel size={20} /></div>
              <h3 className="text-xl font-black text-[#2D3436]">住宿預訂</h3>
            </div>
            <button onClick={() => { resetForms(); setNewBooking({type: BookingType.ACCOMMODATION}); setIsModalOpen(true); }} className="px-4 py-2 bg-white text-purple-600 border border-purple-100 rounded-xl font-bold text-sm hover:bg-purple-50 transition-all flex items-center gap-2 shadow-sm">
              <Plus size={16} /> 新增住宿
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {(trip.bookings || []).filter(b => b.type === BookingType.ACCOMMODATION).map(booking => (
              <motion.div 
                layout 
                key={booking.id} 
                onClick={() => openAccEdit(booking)}
                className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100 hover:shadow-md transition-all group cursor-pointer"
              >
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h4 className="text-xl font-black text-[#2D3436] mb-1">{booking.title}</h4>
                    <div className="flex items-center gap-2 text-xs font-bold text-[#BC002D]">
                      <Calendar size={14} />
                      <span>{booking.checkInDate} — {booking.checkOutDate}</span>
                    </div>
                  </div>
                  <button onClick={(e) => deleteBooking(e, booking.id)} className="p-2 text-gray-200 hover:text-red-500 rounded-xl transition-colors"><Trash2 size={18} /></button>
                </div>
                <div className="flex items-start gap-2 mb-6 text-gray-500 text-sm">
                  <MapPin size={16} className="mt-0.5 shrink-0 text-gray-300" />
                  <p className="line-clamp-2">{booking.location}</p>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={(e) => { e.stopPropagation(); openMaps(booking.location); }}
                    className="flex-1 py-3 bg-gray-50 hover:bg-[#BC002D] hover:text-white rounded-2xl text-gray-500 font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-2"
                  >
                    <MapIcon size={14} /> 查看地圖
                  </button>
                  <div className="p-3 bg-gray-50 text-gray-400 rounded-2xl group-hover:bg-purple-50 group-hover:text-purple-500 transition-colors">
                    <Search size={16} />
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </div>

      {/* 整合彈窗 */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="bg-white rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden">
              <h3 className="text-2xl font-black mb-8 text-[#2D3436] tracking-tight">
                {editingBookingId ? '修改預約項目 ✏️' : `新增${newBooking.type === BookingType.FLIGHT ? '機票' : '住宿'} ✨`}
              </h3>

              <div className="space-y-6">
                {newBooking.type === BookingType.FLIGHT ? (
                  <div className="space-y-5">
                    <div className="p-6 bg-blue-50/50 rounded-3xl border border-blue-100/30 space-y-4">
                      <div className="text-[10px] font-black text-blue-600 uppercase tracking-widest">航班資訊 {editingBookingId && '(修改後將自動重查)'}</div>
                      <div className="grid grid-cols-2 gap-4">
                        <input className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-blue-200 uppercase" placeholder="航班編號" value={flightInfo.outboundNo} onChange={e => setFlightInfo({...flightInfo, outboundNo: e.target.value})} />
                        <input type="date" className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-blue-200" value={flightInfo.outboundDate} onChange={e => setFlightInfo({...flightInfo, outboundDate: e.target.value})} />
                      </div>
                    </div>

                    {!editingBookingId && (
                      <div className="p-6 bg-pink-50/50 rounded-3xl border border-pink-100/30 space-y-4">
                        <div className="text-[10px] font-black text-pink-600 uppercase tracking-widest">回程航班 (選填)</div>
                        <div className="grid grid-cols-2 gap-4">
                          <input className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-pink-200 uppercase" placeholder="航班編號" value={flightInfo.returnNo} onChange={e => setFlightInfo({...flightInfo, returnNo: e.target.value})} />
                          <input type="date" className="px-5 py-4 rounded-2xl bg-white text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-pink-200" value={flightInfo.returnDate} onChange={e => setFlightInfo({...flightInfo, returnDate: e.target.value})} />
                        </div>
                      </div>
                    )}
                    {errors.flight && <p className="text-red-500 text-xs font-bold">{errors.flight}</p>}
                  </div>
                ) : (
                  <div className="space-y-5">
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">住宿名稱</label>
                      <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" placeholder="例如：東京希爾頓酒店" value={accInfo.title} onChange={e => setAccInfo({...accInfo, title: e.target.value})} />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">入住日期</label>
                        <input type="date" className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" value={accInfo.checkIn} onChange={e => setAccInfo({...accInfo, checkIn: e.target.value})} />
                      </div>
                      <div>
                        <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">退房日期</label>
                        <input type="date" className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" value={accInfo.checkOut} onChange={e => setAccInfo({...accInfo, checkOut: e.target.value})} />
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">住宿地址 (供地圖搜尋)</label>
                      <input className="w-full px-5 py-4 rounded-2xl bg-gray-50 text-[#2D3436] font-bold outline-none border-2 border-transparent focus:border-[#BC002D]/20" placeholder="輸入詳細地址..." value={accInfo.address} onChange={e => setAccInfo({...accInfo, address: e.target.value})} />
                    </div>
                    {errors.acc && <p className="text-red-500 text-xs font-bold">{errors.acc}</p>}
                  </div>
                )}
              </div>

              <div className="flex gap-4 mt-10">
                <button onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-gray-500 font-bold hover:bg-gray-50 rounded-2xl transition-all">取消</button>
                <button onClick={handleSaveBooking} className="flex-[2] py-4 bg-[#2D3436] text-white rounded-2xl font-bold shadow-lg hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-2">
                  儲存並同步
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default BookingManagement;

import React, { useState } from 'react';
