            )}
          </div>
        </div>

        <div>
          <div className="flex justify-between items-end mb-2">
            <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">
              {countdown > 0 ? '距離出發還有' : '旅程進行中'}
            </span>
