import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Sun, Cloud, CloudSun, CloudRain, CloudSnow, 
  Plus, Utensils, Camera, TrainFront, Hotel, ShoppingBag,
  Clock, MapPin, Trash2, AlertCircle
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, ActivityType, Activity } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

const TypeIcon = ({ type, contrast = false }: { type: ActivityType, contrast?: boolean }) => {
  if (contrast) return null;
  switch (type) {
    case ActivityType.FOOD: return <Utensils size={18} className="text-orange-500" />;
    case ActivityType.SIGHTSEEING: return <Camera size={18} className="text-blue-500" />;
    case ActivityType.TRANSPORT: return <TrainFront size={18} className="text-green-500" />;
    case ActivityType.HOTEL: return <Hotel size={18} className="text-purple-500" />;
    case ActivityType.SHOPPING: return <ShoppingBag size={18} className="text-pink-500" />;
    default: return <MapPin size={18} className="text-gray-500" />;
  }
};

const WeatherIcon = ({ condition, isActive = false }: { condition?: string, isActive?: boolean }) => {
  const colorClass = isActive ? "text-white" : "";
  switch (condition) {
    case 'Sunny': return <Sun size={20} className={isActive ? colorClass : "text-yellow-500"} />;
    case 'Cloudy': return <Cloud size={20} className={isActive ? colorClass : "text-gray-400"} />;
    case 'CloudSun': return <CloudSun size={20} className={isActive ? colorClass : "text-orange-400"} />;
    case 'Rain': return <CloudRain size={20} className={isActive ? colorClass : "text-blue-400"} />;
    case 'Snow': return <CloudSnow size={20} className={isActive ? colorClass : "text-indigo-300"} />;
    default: return <Sun size={20} className={isActive ? colorClass : "text-yellow-500"} />;
  }
};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId, themeColor } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingActivityId, setEditingActivityId] = useState<string | null>(null);
  const [errors, setErrors] = useState<any>({});

  const initialActivityState: Partial<Activity> = {
    time: '10:00',
    type: ActivityType.SIGHTSEEING,
    location: '',
    note: '',
    cost: 0
  };

  const [newActivity, setNewActivity] = useState<Partial<Activity>>(initialActivityState);

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-20 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const handleSaveActivity = () => {
    if (!newActivity.location) { setErrors({location: '請輸入地點'}); return; }

    const activityData: Activity = {
      id: editingActivityId || Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...(trip.dailyItinerary || [])];
    const dayIndex = updatedItinerary.findIndex(i => i.day === activeDay);

    if (dayIndex > -1) {
      let activities = [...updatedItinerary[dayIndex].activities];
      if (editingActivityId) activities = activities.map(a => a.id === editingActivityId ? activityData : a);
      else activities.push(activityData);
      updatedItinerary[dayIndex] = { ...updatedItinerary[dayIndex], activities: activities.sort((a, b) => a.time.localeCompare(b.time)) };
    } else {
      updatedItinerary.push({ day: activeDay, date: currentItinerary.date, activities: [activityData] });
    }

    updateTrip({ ...trip, dailyItinerary: updatedItinerary });
    setIsModalOpen(false);
    setNewActivity(initialActivityState);
  };

  const deleteActivity = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = trip.dailyItinerary.map(day => day.day === activeDay ? { ...day, activities: day.activities.filter(a => a.id !== id) } : day);
    updateTrip({ ...trip, dailyItinerary: updated });
  };

  const totalDays = Math.ceil((new Date(trip.endDate).getTime() - new Date(trip.startDate).getTime()) / 86400000) + 1;
  const dayButtons = Array.from({ length: totalDays }, (_, i) => i + 1);

  return (
    <div className="flex flex-col lg:flex-row gap-8">
      <aside className="lg:w-80 flex flex-col gap-2">
        <div className="grid grid-cols-1 gap-2">
          {dayButtons.map(dayNum => {
            const isActive = activeDay === dayNum;
            const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
            return (
              <button
                key={dayNum}
                onClick={() => setActiveDay(dayNum)}
                className={`flex items-center justify-between px-6 py-4 rounded-2xl transition-all
                  ${isActive ? 'theme-bg-primary text-white shadow-lg' : 'bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-muted)]'}`}
              >
                <span className="text-sm font-black uppercase">Day {dayNum}</span>
                <WeatherIcon condition={dayData?.weather?.condition} isActive={isActive} />
              </button>
            );
          })}
        </div>
      </aside>

      <section className="flex-1 space-y-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-3xl font-black theme-text-contrast tracking-tight">行程規劃</h2>
            <p className="text-[var(--text-muted)] font-bold">DAY {activeDay} • {currentItinerary.date}</p>
          </div>
          <button onClick={() => setIsModalOpen(true)} className="theme-bg-primary text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 shadow-lg">
            <Plus size={20} /> 新增活動
          </button>
        </div>

        <div className="relative">
          <div className="absolute left-[31px] top-6 bottom-6 w-[2px] bg-gray-100/10 z-0" />
          <div className="space-y-6">
            {currentItinerary.activities.map((activity) => (
              <motion.div layout key={activity.id} onClick={() => { setNewActivity(activity); setEditingActivityId(activity.id); setIsModalOpen(true); }} className="relative pl-16 group cursor-pointer">
                <div className="absolute left-[24px] top-1/2 -translate-y-1/2 w-4 h-4 rounded-full bg-[var(--bg-main)] border-4 theme-border-primary shadow-[0_0_0_4px_var(--bg-main)] z-10" />
                <div className="bg-[var(--bg-card)] p-6 rounded-[1.5rem] shadow-sm border border-[var(--border-color)] flex items-center gap-6">
                  <div className="font-black text-[var(--text-main)] min-w-[60px]">{activity.time}</div>
                  <div className="p-3 rounded-xl theme-bg-soft"><TypeIcon type={activity.type} /></div>
                  <div className="flex-1">
                    <h4 className="font-bold theme-text-contrast">{activity.location}</h4>
                    <span className="text-[10px] theme-primary font-black uppercase tracking-widest">{activity.type}</span>
                  </div>
                  <button onClick={(e) => deleteActivity(e, activity.id)} className="p-2 text-gray-200 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* 彈窗對接主題 */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsModalOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-[var(--bg-card)] rounded-[2.5rem] w-full max-w-lg p-10 relative shadow-2xl overflow-hidden">
              <h3 className="text-2xl font-black mb-8 theme-text-contrast tracking-tight">編輯行程</h3>
              <div className="space-y-6">
                <input className="w-full px-5 py-4 rounded-2xl bg-gray-50/5 text-[var(--text-main)] font-bold border-2 border-transparent focus:theme-border-primary outline-none" placeholder="地點" value={newActivity.location} onChange={e => setNewActivity({...newActivity, location: e.target.value})} />
                <div className="grid grid-cols-2 gap-4">
                  <input type="time" className="px-5 py-4 rounded-2xl bg-gray-50/5 text-[var(--text-main)] outline-none" value={newActivity.time} onChange={e => setNewActivity({...newActivity, time: e.target.value})} />
                  <input type="number" className="px-5 py-4 rounded-2xl bg-gray-50/5 text-[var(--text-main)] outline-none" placeholder="預算" value={newActivity.cost} onChange={e => setNewActivity({...newActivity, cost: parseInt(e.target.value) || 0})} />
                </div>
              </div>
              <div className="flex gap-4 mt-10">
                <button onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-gray-400 font-bold">取消</button>
                <button onClick={handleSaveActivity} className="flex-[2] py-4 theme-bg-primary text-white rounded-2xl font-bold">儲存</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default TripDetail;

import React from 'react';
import { useParams } from 'react-router-dom';
