const BudgetPage: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, themeColor } = useTrips();
  const trip = getTripById(tripId || '');

  if (!trip) return <div>Trip not found</div>;

  const categorySpending = (trip.dailyItinerary || []).reduce((acc, day) => {
    day.activities.forEach(act => {
      acc[act.type] = (acc[act.type] || 0) + act.cost;
    });
    return acc;
  }, {} as Record<string, number>);

  const data = Object.entries(categorySpending).map(([name, value]) => ({ name, value }));
  const totalSpent = Object.values(categorySpending).reduce((a, b) => a + b, 0);
  const remaining = (trip.budget?.total || 0) - totalSpent;
  const isOverBudget = remaining < 0;

  const categoryIcons: Record<string, any> = {
    [ActivityType.FOOD]: { icon: <Utensils size={18} />, color: 'bg-orange-500' },
    [ActivityType.SIGHTSEEING]: { icon: <Camera size={18} />, color: 'bg-blue-500' },
    [ActivityType.TRANSPORT]: { icon: <TrainFront size={18} />, color: 'bg-green-500' },
    [ActivityType.HOTEL]: { icon: <Hotel size={18} />, color: 'bg-purple-500' },
    [ActivityType.SHOPPING]: { icon: <ShoppingBag size={18} />, color: 'bg-pink-500' },
    'Other': { icon: <Box size={18} />, color: 'bg-slate-400' }
  };

  return (
    <div className="space-y-10">
      <div>
        <h1 className="text-4xl font-extrabold theme-text-contrast tracking-tight mb-2">預算追蹤</h1>
        <p className="text-[var(--text-muted)] font-medium">掌控你的旅程每一分開支 💰</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-[var(--bg-card)] p-8 rounded-[2.5rem] border border-[var(--border-color)] shadow-sm">
            <span className="text-xs font-black text-[var(--text-muted)] uppercase tracking-widest mb-4 block">總預算額度</span>
            <div className="flex items-end gap-3">
              <span className="text-4xl font-black theme-text-contrast">¥ {(trip.budget?.total || 0).toLocaleString()}</span>
              <button onClick={() => { const b = prompt('預算', '10000'); if(b) updateTrip({...trip, budget:{...trip.budget, total: parseInt(b)}}); }} className="text-xs theme-primary font-black theme-bg-soft p-1.5 rounded-lg">修改</button>
            </div>
          </div>

          <div className={`p-8 rounded-[2.5rem] border shadow-sm ${isOverBudget ? 'bg-red-500 text-white' : 'bg-[var(--bg-card)] border-[var(--border-color)]'}`}>
            <span className={`text-xs font-black uppercase tracking-widest mb-4 block ${isOverBudget ? 'text-white/80' : 'text-[var(--text-muted)]'}`}>
              {isOverBudget ? '超額支出警告' : '目前剩餘金額'}
            </span>
            <div className="flex items-center justify-between">
              <span className={`text-4xl font-black ${isOverBudget ? 'text-white' : 'text-green-500'}`}>¥ {Math.abs(remaining).toLocaleString()}</span>
              {isOverBudget && <AlertCircle size={32} />}
            </div>
          </div>

          <div className="md:col-span-2 bg-[var(--bg-card)] p-10 rounded-[2.5rem] border border-[var(--border-color)] shadow-sm">
            <h3 className="text-xl font-black mb-8 theme-text-contrast tracking-tight">支出分類</h3>
            <div className="space-y-8">
              {Object.keys(ActivityType).map((key) => {
                const type = ActivityType[key as keyof typeof ActivityType];
                const amount = categorySpending[type] || 0;
                const percentage = totalSpent > 0 ? (amount / totalSpent) * 100 : 0;
                return (
                  <div key={type} className="flex items-center gap-6 group">
