                      <div className="h-2 w-full bg-gray-100/10 rounded-full overflow-hidden">
                        <motion.div initial={{ width: 0 }} animate={{ width: `${percentage}%` }} className={`h-full ${categoryIcons[type].color}`} />
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="bg-[var(--bg-card)] p-10 rounded-[2.5rem] border border-[var(--border-color)] shadow-sm flex flex-col items-center justify-center">
          <div className="w-full h-[280px] relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={data} innerRadius={80} outerRadius={100} paddingAngle={5} dataKey="value">
                  {data.map((_, i) => <Cell key={i} fill={themeColor} fillOpacity={0.2 + (i*0.2)} />)}
