  return (
    <div className="space-y-8">
      <AnimatePresence>
        {(isBackgroundSyncing || syncStatus) && (
          <motion.div 
            initial={{ y: -50, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -50, opacity: 0 }}
            className="fixed top-4 left-1/2 -translate-x-1/2 z-[100] w-[90%] max-w-xs"
          >
            <div className={`p-4 rounded-xl shadow-xl flex items-center gap-3 border transition-colors ${
              syncStatus === 'success' ? 'bg-[#00A86B] border-white/20 text-white' :
              syncStatus === 'error' ? 'bg-[#BC002D] border-white/20 text-white' :
              'bg-[#2D3436] border-white/5 text-white'
            }`}>
              {isBackgroundSyncing ? <Loader2 size={16} className="animate-spin" /> : 
               syncStatus === 'success' ? <CheckCircle2 size={16} /> : <AlertTriangle size={16} />}
              <div className="flex-1">
                <p className="text-[10px] font-black uppercase tracking-wider">
                  {isBackgroundSyncing ? '背景同步中' : syncStatus === 'success' ? '同步成功' : '同步失敗'}
                </p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black text-[#2D3436] dark:text-white tracking-tight">預約管理</h1>
          <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">機票與住宿同步</p>
        </div>
      </div>

      <div className="space-y-10">
        <div className="space-y-4">
          <div className="flex items-center justify-between">
