            </div>
            <button onClick={() => { resetForms(); setNewBooking({type: BookingType.FLIGHT}); setIsModalOpen(true); }} className="px-3 py-1.5 bg-white text-blue-600 border border-blue-100 rounded-lg font-bold text-[10px] uppercase shadow-sm">
