import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  CheckCircle2, Circle, Plus, Trash2, 
  RefreshCcw, ArrowRightLeft, DollarSign, Info
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { motion } from 'framer-motion';

const Toolbox: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  const [newItem, setNewItem] = useState('');
  const [jpyAmount, setJpyAmount] = useState('1000');
  const [hkdAmount, setHkdAmount] = useState('55');
  const exchangeRate = 0.051; 

  useEffect(() => {
    const jpy = parseFloat(jpyAmount);
    if (!isNaN(jpy)) {
      setHkdAmount((jpy * exchangeRate).toFixed(2));
    }
  }, [jpyAmount]);

  if (!trip) return <div className="p-10 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const toggleCheck = (id: string) => {
    const updated = trip.checklist.map(item => 
      item.id === id ? { ...item, completed: !item.completed } : item
    );
    updateTrip({ ...trip, checklist: updated });
  };

  const deleteItem = (id: string) => {
    const updated = trip.checklist.filter(item => item.id !== id);
    updateTrip({ ...trip, checklist: updated });
  };

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.trim()) return;
    const item = { id: Math.random().toString(36).substr(2, 9), item: newItem, completed: false };
    updateTrip({ ...trip, checklist: [...trip.checklist, item] });
    setNewItem('');
  };

  const completedCount = trip.checklist.filter(i => i.completed).length;
  const progress = trip.checklist.length > 0 ? (completedCount / trip.checklist.length) * 100 : 0;

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-2xl font-black text-[#2D3436] dark:text-white tracking-tight">旅行工具箱</h1>
        <p className="text-gray-500 text-xs font-bold uppercase tracking-widest">行前準備與匯率</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Checklist */}
        <div className="bg-[var(--bg-card)] p-6 rounded-2xl shadow-sm border border-[var(--border-color)] flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-black tracking-tight">行前清單</h3>
            <span className="text-[10px] font-black theme-bg-soft theme-primary px-3 py-1 rounded-full uppercase tracking-widest">
              {completedCount} / {trip.checklist.length}
            </span>
          </div>

          <div className="mb-6">
            <div className="flex justify-between text-[9px] font-bold text-gray-400 uppercase tracking-widest mb-2">
              <span>進度</span>
              <span className="theme-primary">{progress.toFixed(0)}%</span>
            </div>
            <div className="h-2 w-full bg-gray-100/10 rounded-full overflow-hidden">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                className="h-full theme-bg-primary"
              />
            </div>
          </div>

          <form onSubmit={addItem} className="flex gap-2 mb-6">
            <input 
              className="flex-1 px-4 py-2.5 rounded-xl bg-gray-50/10 text-xs font-bold border border-[var(--border-color)] outline-none focus:theme-border-primary transition-all"
              placeholder="新增清單項目..."
              value={newItem}
              onChange={e => setNewItem(e.target.value)}
            />
            <button className="p-2.5 theme-bg-primary text-white rounded-xl shadow-md transition-transform active:scale-95 shrink-0">
              <Plus size={20} />
            </button>
          </form>

          <div className="space-y-1 max-h-[300px] overflow-y-auto pr-1 flex-1 scrollbar-hide">
            {trip.checklist.map(item => (
              <div key={item.id} className="flex items-center justify-between p-3 rounded-xl hover:bg-gray-50/5 transition-all">
                <button 
                  onClick={() => toggleCheck(item.id)}
                  className="flex items-center gap-3 flex-1 text-left"
                >
                  {item.completed ? (
                    <div className="p-0.5 bg-[#00A86B]/10 rounded-full"><CheckCircle2 className="text-[#00A86B]" size={18} /></div>
                  ) : (
                    <Circle className="text-gray-300" size={18} />
                  )}
                  <span className={`text-xs font-bold transition-all ${item.completed ? 'text-gray-400 line-through' : ''}`}>
                    {item.item}
                  </span>
                </button>
                <button 
                  onClick={() => deleteItem(item.id)}
                  className="p-1.5 text-gray-200 hover:text-red-500"
                >
                  <Trash2 size={14} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Currency Converter */}
        <div className="bg-[var(--bg-card)] p-6 rounded-2xl shadow-sm border border-[var(--border-color)] flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-lg font-black tracking-tight">匯率換算</h3>
            <RefreshCcw size={14} className="theme-primary opacity-50" />
          </div>

          <div className="space-y-6 flex-1 flex flex-col justify-center">
            <div className="space-y-4">
              <div className="relative">
                <label className="block text-[8px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-2">日圓 (JPY)</label>
                <div className="flex items-center bg-gray-50/5 rounded-xl px-4 py-3 border border-[var(--border-color)]">
                  <span className="text-xl font-black theme-primary mr-3">¥</span>
                  <input 
                    type="number"
                    className="flex-1 bg-transparent text-xl font-black outline-none"
                    value={jpyAmount}
                    onChange={e => setJpyAmount(e.target.value)}
                  />
                </div>
              </div>

              <div className="flex justify-center -my-6 relative z-10">
                <div className="bg-[var(--bg-main)] theme-primary p-2.5 rounded-full shadow-lg border-4 border-[var(--bg-card)]">
                  <ArrowRightLeft size={16} />
                </div>
              </div>

              <div className="relative">
                <label className="block text-[8px] font-black text-gray-400 uppercase tracking-widest mb-1 ml-2">港幣 (HKD)</label>
                <div className="flex items-center bg-gray-50/5 rounded-xl px-4 py-3 border border-[var(--border-color)]">
                  <span className="text-xl font-black text-gray-300 mr-3">$</span>
                  <input 
                    readOnly
                    className="flex-1 bg-transparent text-xl font-black text-[#00A86B] outline-none"
                    value={hkdAmount}
                  />
                </div>
              </div>
            </div>

            <div className="bg-gray-50/5 p-4 rounded-xl border border-[var(--border-color)] flex items-start gap-3 mt-4">
              <Info className="theme-primary shrink-0 mt-0.5" size={14} />
              <p className="text-[9px] font-bold text-gray-500 leading-tight">
                當前市場參考匯率：<span className="theme-primary">1 JPY ≈ {exchangeRate} HKD</span>。
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Toolbox;

import React, { useState } from 'react';
import { Plus, Calendar, MapPin, MoreVertical, Trash2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
