                          <input type="date" className="px-3 py-2 rounded-lg bg-[var(--bg-main)] font-bold text-xs theme-text-contrast border border-[var(--border-color)] outline-none" value={flightInfo.returnDate} onChange={e => setFlightInfo({...flightInfo, returnDate: e.target.value})} />
