                    <div className="grid grid-cols-2 gap-3">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">入住日</label>
                        <input type="date" className="w-full px-3 py-2.5 rounded-lg bg-[var(--bg-main)] font-bold text-xs theme-text-contrast border border-[var(--border-color)] outline-none" value={accInfo.checkIn} onChange={e => setAccInfo({...accInfo, checkIn: e.target.value})} />
                      </div>
