import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Sun, Cloud, CloudSun, CloudRain, CloudSnow, 
  Plus, Utensils, Camera, TrainFront, Hotel, ShoppingBag,
  Clock, MapPin, Trash2, AlertCircle, GripVertical, Info
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, ActivityType, Activity } from '../types';
import { motion, AnimatePresence, Reorder } from 'framer-motion';

const TypeIcon = ({ type }: { type: ActivityType }) => {
  switch (type) {
    case ActivityType.FOOD: return <Utensils size={14} className="text-orange-500" />;
    case ActivityType.SIGHTSEEING: return <Camera size={14} className="text-blue-500" />;
    case ActivityType.TRANSPORT: return <TrainFront size={14} className="text-green-500" />;
    case ActivityType.HOTEL: return <Hotel size={14} className="text-purple-500" />;
    case ActivityType.SHOPPING: return <ShoppingBag size={14} className="text-pink-500" />;
    default: return <MapPin size={14} className="text-gray-500" />;
  }
};

const WeatherIcon = ({ condition, isActive = false }: { condition?: string, isActive?: boolean }) => {
  const colorClass = isActive ? "text-white" : "";
  switch (condition) {
    case 'Sunny': return <Sun size={16} className={isActive ? colorClass : "text-yellow-500"} />;
    case 'Cloudy': return <Cloud size={16} className={isActive ? colorClass : "text-gray-400"} />;
    case 'CloudSun': return <CloudSun size={16} className={isActive ? colorClass : "text-orange-400"} />;
    case 'Rain': return <CloudRain size={16} className={isActive ? colorClass : "text-blue-400"} />;
    case 'Snow': return <CloudSnow size={16} className={isActive ? colorClass : "text-indigo-300"} />;
    default: return <Sun size={16} className={isActive ? colorClass : "text-yellow-500"} />;
  }
};

const TripDetail: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [activeDay, setActiveDay] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingActivityId, setEditingActivityId] = useState<string | null>(null);

  const initialActivityState: Partial<Activity> = { 
    time: '10:00', 
    type: ActivityType.SIGHTSEEING, 
    location: '', 
    note: '', 
    cost: 0 
  };
  const [newActivity, setNewActivity] = useState<Partial<Activity>>(initialActivityState);

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-10 text-center text-gray-400 font-bold uppercase tracking-widest">找不到該旅程資料</div>;

  const currentItinerary = trip.dailyItinerary.find(i => i.day === activeDay) || {
    day: activeDay,
    date: new Date(new Date(trip.startDate).getTime() + (activeDay - 1) * 86400000).toISOString().split('T')[0],
    activities: []
  };

  const activities = currentItinerary.activities;

  const handleSaveActivity = () => {
    if (!newActivity.location) return;
    const activityData: Activity = {
      id: editingActivityId || Math.random().toString(36).substr(2, 9),
      time: newActivity.time || '10:00',
      type: newActivity.type as ActivityType,
      location: newActivity.location || '',
      note: newActivity.note || '',
      cost: Number(newActivity.cost) || 0
    };

    const updatedItinerary = [...(trip.dailyItinerary || [])];
    const dayIndex = updatedItinerary.findIndex(i => i.day === activeDay);

    if (dayIndex > -1) {
      let dayActivities = [...updatedItinerary[dayIndex].activities];
      if (editingActivityId) {
        dayActivities = dayActivities.map(a => a.id === editingActivityId ? activityData : a);
      } else {
        dayActivities.push(activityData);
        dayActivities.sort((a, b) => a.time.localeCompare(b.time));
      }
      updatedItinerary[dayIndex] = { ...updatedItinerary[dayIndex], activities: dayActivities };
    } else {
      updatedItinerary.push({ day: activeDay, date: currentItinerary.date, activities: [activityData] });
    }

    updateTrip({ ...trip, dailyItinerary: updatedItinerary });
    setIsModalOpen(false);
    setNewActivity(initialActivityState);
    setEditingActivityId(null);
  };

  const handleReorder = (newOrder: Activity[]) => {
    const updatedItinerary = trip.dailyItinerary.map(day => 
      day.day === activeDay ? { ...day, activities: newOrder } : day
    );
    updateTrip({ ...trip, dailyItinerary: updatedItinerary });
  };

  const deleteActivity = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = trip.dailyItinerary.map(day => 
      day.day === activeDay ? { ...day, activities: day.activities.filter(a => a.id !== id) } : day
    );
    updateTrip({ ...trip, dailyItinerary: updated });
  };

  const totalDays = Math.ceil((new Date(trip.endDate).getTime() - new Date(trip.startDate).getTime()) / 86400000) + 1;
  const dayButtons = Array.from({ length: totalDays }, (_, i) => i + 1);

  return (
    <div className="space-y-6">
      {/* 置頂滾動日期列 */}
      <nav className="sticky top-0 z-40 -mx-4 px-4 py-2 bg-[var(--bg-main)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="flex gap-2 overflow-x-auto scrollbar-hide snap-x py-1">
          {dayButtons.map(dayNum => {
            const isActive = activeDay === dayNum;
            const dayData = trip.dailyItinerary.find(d => d.day === dayNum);
            return (
              <button
                key={dayNum}
                onClick={() => setActiveDay(dayNum)}
                className={`flex items-center gap-3 shrink-0 px-5 py-2.5 rounded-2xl transition-all snap-start
                  ${isActive ? 'theme-bg-primary text-white shadow-lg scale-105' : 'bg-[var(--bg-card)] border border-[var(--border-color)] text-[var(--text-muted)] hover:bg-gray-50/5'}`}
              >
                <div className="flex flex-col items-start">
                  <span className="text-[10px] font-black leading-none opacity-60">DAY</span>
                  <span className="text-sm font-black leading-none mt-1">{dayNum}</span>
                </div>
                <WeatherIcon condition={dayData?.weather?.condition} isActive={isActive} />
              </button>
            );
          })}
        </div>
      </nav>

      <section className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-xl font-black theme-text-contrast tracking-tight uppercase">Day {activeDay} 行程</h2>
            <p className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest">{currentItinerary.date}</p>
          </div>
          <button onClick={() => { setNewActivity(initialActivityState); setEditingActivityId(null); setIsModalOpen(true); }} className="theme-bg-primary text-white p-2 rounded-xl shadow-md active:scale-95 transition-transform">
            <Plus size={20} />
          </button>
        </div>

        <div className="relative">
          <div className="absolute left-[15px] top-4 bottom-4 w-[1.5px] bg-gray-100/10 z-0" />

          <Reorder.Group axis="y" values={activities} onReorder={handleReorder} className="space-y-3">
            {activities.length === 0 && (
              <p className="text-center py-10 text-[10px] text-gray-400 font-bold uppercase tracking-widest">目前尚無安排行程</p>
            )}
            {activities.map((activity) => (
              <Reorder.Item 
                key={activity.id} 
                value={activity}
                className="relative pl-10 group cursor-grab active:cursor-grabbing"
              >
                <div className="absolute left-[10px] top-1/2 -translate-y-1/2 w-2.5 h-2.5 rounded-full bg-[var(--bg-main)] border-2 theme-border-primary z-10" />
                <div 
                  onClick={() => { setNewActivity(activity); setEditingActivityId(activity.id); setIsModalOpen(true); }}
                  className="bg-[var(--bg-card)] p-3 rounded-xl shadow-sm border border-[var(--border-color)] flex items-start gap-4 hover:border-gray-300 dark:hover:border-white/20 transition-all"
                >
                  <div className="text-[10px] font-black theme-text-contrast min-w-[40px] mt-1">{activity.time}</div>
                  <div className="flex-1 min-w-0 space-y-1">
                    <div className="flex items-center gap-2">
                      <div className="p-1 rounded-md theme-bg-soft shrink-0"><TypeIcon type={activity.type} /></div>
                      <h4 className="text-xs font-bold theme-text-contrast truncate flex-1">{activity.location}</h4>
                      {activity.cost > 0 && (
                        <span className="text-[10px] font-black theme-primary whitespace-nowrap">¥{activity.cost.toLocaleString()}</span>
                      )}
                    </div>
                    {activity.note && (
                      <p className="text-[10px] text-[var(--text-muted)] font-medium line-clamp-1 italic pl-7 border-l-2 border-gray-100 dark:border-white/5 ml-1">
                        {activity.note}
                      </p>
                    )}
                  </div>
                  <div className="flex flex-col items-center gap-2">
                    <div className="text-gray-200 group-hover:text-gray-400 transition-colors"><GripVertical size={14} /></div>
                    <button onClick={(e) => deleteActivity(e, activity.id)} className="p-1 text-gray-200 hover:text-red-500 transition-colors">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              </Reorder.Item>
            ))}
          </Reorder.Group>
        </div>
      </section>

      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
            <motion.div 
              initial={{ scale: 0.95, opacity: 0 }} 
              animate={{ scale: 1, opacity: 1 }} 
              exit={{ scale: 0.95, opacity: 0 }} 
              className="bg-[var(--bg-card)] rounded-2xl w-full max-w-sm p-6 relative shadow-2xl overflow-hidden border border-[var(--border-color)]"
            >
              <div className="flex items-center gap-2 mb-6">
                <div className="p-1.5 rounded-lg theme-bg-soft theme-primary"><Plus size={18} /></div>
                <h3 className="text-lg font-black theme-text-contrast tracking-tight">
                  {editingActivityId ? '編輯行程' : '新增行程項目'}
                </h3>
              </div>

              <div className="space-y-4">
                <div className="space-y-1.5">
                  <label className="flex items-center gap-1.5 text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">
                    <MapPin size={10} /> 行程地點 / 名稱
                  </label>
                  <input 
                    className="w-full px-4 py-2.5 rounded-xl bg-gray-50/10 text-xs font-bold border border-[var(--border-color)] outline-none focus:theme-border-primary theme-text-contrast" 
                    placeholder="例如：淺草寺、一蘭拉麵" 
                    value={newActivity.location} 
                    onChange={e => setNewActivity({...newActivity, location: e.target.value})} 
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1.5">
                    <label className="flex items-center gap-1.5 text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">
                      <Clock size={10} /> 開始時間
                    </label>
                    <input 
                      type="time" 
                      onClick={(e) => (e.target as any).showPicker?.()}
                      className="w-full px-4 py-2.5 rounded-xl bg-gray-50/10 text-xs font-bold border border-[var(--border-color)] outline-none theme-text-contrast cursor-pointer" 
                      value={newActivity.time} 
                      onChange={e => setNewActivity({...newActivity, time: e.target.value})} 
                    />
                  </div>
                  <div className="space-y-1.5">
                    <label className="flex items-center gap-1.5 text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">
                      ¥ 預計消費
                    </label>
                    <input 
                      type="number" 
                      className="w-full px-4 py-2.5 rounded-xl bg-gray-50/10 text-xs font-bold border border-[var(--border-color)] outline-none theme-text-contrast" 
                      placeholder="日圓額度" 
                      value={newActivity.cost} 
                      onChange={e => setNewActivity({...newActivity, cost: parseInt(e.target.value) || 0})} 
                    />
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="flex items-center gap-1.5 text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">
                    <Info size={10} /> 行程描述 / 備註
                  </label>
                  <textarea 
                    className="w-full px-4 py-2.5 rounded-xl bg-gray-50/10 text-xs font-medium border border-[var(--border-color)] outline-none focus:theme-border-primary theme-text-contrast min-h-[80px] resize-none" 
                    placeholder="補充詳細內容，如預約編號、想吃的餐點等..." 
                    value={newActivity.note} 
                    onChange={e => setNewActivity({...newActivity, note: e.target.value})} 
                  />
                </div>

                <div className="space-y-2">
                   <label className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest ml-1">活動類型</label>
                   <div className="flex flex-wrap gap-2">
                      {Object.values(ActivityType).map((type) => (
                        <button
                          key={type}
                          onClick={() => setNewActivity({...newActivity, type})}
                          className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase border transition-all ${newActivity.type === type ? 'theme-bg-primary text-white border-transparent' : 'bg-gray-50/10 text-gray-400 border-[var(--border-color)]'}`}
                        >
                          {type}
                        </button>
                      ))}
                   </div>
                </div>
              </div>

              <div className="flex gap-3 mt-8">
                <button onClick={() => setIsModalOpen(false)} className="flex-1 py-3 text-xs text-gray-400 font-bold uppercase tracking-widest">取消</button>
                <button onClick={handleSaveActivity} className="flex-[1.5] py-3 theme-bg-primary text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg active:scale-95 transition-transform">
                  儲存行程
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default TripDetail;

import React from 'react';
import { useParams } from 'react-router-dom';
import { useTrips } from '../store/TripContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Utensils, Camera, TrainFront, Hotel, ShoppingBag, Box, AlertCircle } from 'lucide-react';
import { ActivityType } from '../types';
import { motion } from 'framer-motion';

const BudgetPage: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip } = useTrips();
  const trip = getTripById(tripId || '');

  if (!trip) return <div className="p-10 text-center text-gray-400 font-bold">找不到該旅程資料</div>;

  const categorySpending = (trip.dailyItinerary || []).reduce((acc, day) => {
    day.activities.forEach(act => {
      acc[act.type] = (acc[act.type] || 0) + act.cost;
    });
    return acc;
  }, {} as Record<string, number>);

  const totalSpent = Object.values(categorySpending).reduce((a, b) => a + b, 0);
  const totalBudget = trip.budget?.total || 0;
  const remaining = totalBudget - totalSpent;
  const isOverBudget = remaining < 0;

  const handleBudgetChange = (val: string) => {
    const newTotal = parseInt(val) || 0;
    updateTrip({
      ...trip,
      budget: { ...trip.budget, total: newTotal }
    });
  };

  const categoryIcons: Record<string, any> = {
    [ActivityType.FOOD]: { icon: <Utensils size={14} />, color: 'bg-orange-500' },
    [ActivityType.SIGHTSEEING]: { icon: <Camera size={14} />, color: 'bg-blue-500' },
    [ActivityType.TRANSPORT]: { icon: <TrainFront size={14} />, color: 'bg-green-500' },
    [ActivityType.HOTEL]: { icon: <Hotel size={14} />, color: 'bg-purple-500' },
    [ActivityType.SHOPPING]: { icon: <ShoppingBag size={14} />, color: 'bg-pink-500' },
    'Other': { icon: <Box size={14} />, color: 'bg-slate-400' }
  };

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-2xl font-black tracking-tight">預算追蹤</h1>
        <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-widest mt-1">控制每一分支出</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-[var(--bg-card)] p-5 rounded-2xl border border-[var(--border-color)] shadow-sm">
          <label className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-wider mb-2 block ml-1">設定總預算 (JPY)</label>
          <div className="flex items-center gap-2 group">
            <span className="text-xl font-black theme-primary group-focus-within:scale-110 transition-transform">¥</span>
            <input 
              type="number"
              value={totalBudget || ''}
              onChange={(e) => handleBudgetChange(e.target.value)}
              placeholder="0"
              className="w-full bg-transparent text-2xl font-black outline-none theme-text-contrast"
            />
          </div>
        </div>

        <div className={`p-5 rounded-2xl border shadow-sm transition-colors duration-300 ${isOverBudget ? 'bg-red-500 text-white border-red-400 shadow-red-200/20' : 'bg-[var(--bg-card)] border-[var(--border-color)]'}`}>
          <span className={`text-[9px] font-black uppercase tracking-wider mb-2 block ${isOverBudget ? 'text-white/80' : 'text-[var(--text-muted)]'}`}>
            {isOverBudget ? '預算超額' : '剩餘額度'}
          </span>
          <div className="flex items-center justify-between">
            <span className="text-2xl font-black">¥ {Math.abs(remaining).toLocaleString()}</span>
            {isOverBudget && <AlertCircle size={24} className="animate-pulse" />}
          </div>
        </div>
      </div>

      <div className="bg-[var(--bg-card)] p-6 rounded-2xl border border-[var(--border-color)] shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-sm font-black tracking-tight">支出明細與佔比</h3>
          <span className="text-[10px] font-bold text-[var(--text-muted)]">總支出 ¥ {totalSpent.toLocaleString()}</span>
        </div>
        <div className="space-y-6">
          {Object.keys(ActivityType).map((key) => {
            const type = ActivityType[key as keyof typeof ActivityType];
            const amount = categorySpending[type] || 0;
            // 百分比相對於預算或總支出（此處以預算為準，若無預算則以總支出為準）
            const percentage = totalBudget > 0 ? (amount / totalBudget) * 100 : (totalSpent > 0 ? (amount / totalSpent) * 100 : 0);

            return (
              <div key={type} className="flex items-center gap-4">
                <div className={`${categoryIcons[type].color} text-white p-2 rounded-xl shrink-0 shadow-sm`}>{categoryIcons[type].icon}</div>
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between mb-2">
                    <span className="text-xs font-bold theme-text-contrast truncate pr-2 uppercase tracking-wide">{type}</span>
                    <div className="text-right">
                      <span className="text-xs font-black theme-text-contrast">¥ {amount.toLocaleString()}</span>
                      <span className="text-[9px] font-bold text-[var(--text-muted)] ml-2">{percentage.toFixed(1)}%</span>
                    </div>
                  </div>
                  <div className="h-2 w-full bg-gray-100/10 rounded-full overflow-hidden">
                    <motion.div 
                      initial={{ width: 0 }} 
                      animate={{ width: `${Math.min(percentage, 100)}%` }} 
                      transition={{ duration: 0.5, ease: "easeOut" }}
                      className={`h-full ${categoryIcons[type].color} ${percentage > 100 ? 'opacity-80' : ''}`} 
                    />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default BudgetPage;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Plane, 
  Hotel, 
  Ticket, 
  Plus, 
  Clock, 
  MapPin, 
  Trash2, 
  Calendar,
  Loader2,
  Map as MapIcon,
  Search,
  CheckCircle2,
  AlertTriangle,
  ExternalLink
} from 'lucide-react';
import { useTrips } from '../store/TripContext';
import { Trip, BookingType, Booking } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI } from "@google/genai";

const BookingManagement: React.FC = () => {
  const { tripId } = useParams();
  const { getTripById, updateTrip, setLastTripId } = useTrips();
  const trip = getTripById(tripId || '');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBookingId, setEditingBookingId] = useState<string | null>(null);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'success' | 'error' | null>(null);
  const [errors, setErrors] = useState<any>({});

  const [flightInfo, setFlightInfo] = useState({ outboundNo: '', outboundDate: '', returnNo: '', returnDate: '' });
  const [accInfo, setAccInfo] = useState({ title: '', checkIn: '', checkOut: '', address: '' });
  const [newBooking, setNewBooking] = useState<Partial<Booking>>({ type: BookingType.FLIGHT });

  const [searchSources, setSearchSources] = useState<{title: string, uri: string}[]>([]);

  useEffect(() => {
    if (tripId) setLastTripId(tripId);
  }, [tripId, setLastTripId]);

  if (!trip) return <div className="p-10 text-center text-gray-400 font-bold uppercase tracking-widest">找不到該旅程資料</div>;

  const searchFlightWithGoogleSearch = async (flightNo: string, date: string) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `你現在是航班數據查詢助手。請透過 Google 搜尋查詢航班編號「${flightNo}」在「${date}」的實時資訊。
    請搜尋起飛時間、抵達機場、航空公司名稱。

    請務必將結果翻譯為繁體中文，並以 JSON 格式回傳以下內容：
    {
      "airline": "航空公司(繁體中文)",
      "departureTime": "起飛時間(HH:mm)",
      "airport": "起飛機場名稱",
      "terminal": "航站",
      "status": "實時狀態"
    }
    不要回傳任何 JSON 以外的文字。`;

    const timeoutPromise = new Promise((_, reject) => 
      setTimeout(() => reject(new Error('TIMEOUT')), 60000)
    );

    const apiPromise = ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { 
        tools: [{ googleSearch: {} }], 
        responseMimeType: "application/json" 
      }
    });

    const result: any = await Promise.race([apiPromise, timeoutPromise]);

    const sources = result.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const webSources = sources
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      }));

    setSearchSources(prev => [...prev, ...webSources]);

    return JSON.parse(result.text || '{}');
  };

  const handleSaveBooking = async () => {
    setErrors({});
    setSearchSources([]);

    if (newBooking.type === BookingType.FLIGHT) {
      if (!editingBookingId && !flightInfo.outboundNo && !flightInfo.returnNo) {
        setErrors({ flight: '請輸入至少一個航班編號' });
        return;
      }
    } else if (newBooking.type === BookingType.ACCOMMODATION) {
      if (!accInfo.title || !accInfo.checkIn || !accInfo.checkOut) {
        setErrors({ acc: '請完整填寫資訊' });
        return;
      }
    }

    setIsModalOpen(false);
    setIsBackgroundSyncing(true);
    setSyncStatus(null);

    try {
      let updatedBookings = [...(trip.bookings || [])];

      if (newBooking.type === BookingType.FLIGHT) {
        if (editingBookingId) {
          const info = await searchFlightWithGoogleSearch(flightInfo.outboundNo, flightInfo.outboundDate || trip.startDate);
          updatedBookings = updatedBookings.map(b => b.id === editingBookingId ? {
            ...b,
            airline: info?.airline || '未知航空公司',
            date: flightInfo.outboundDate || trip.startDate,
            time: info?.departureTime || '待定',
            location: info?.airport || '待確認機場',
            terminal: info?.terminal || '-',
            flightNumber: flightInfo.outboundNo.toUpperCase()
          } : b);
        } else {
          const flights = [];
          if (flightInfo.outboundNo) flights.push({ no: flightInfo.outboundNo, date: flightInfo.outboundDate || trip.startDate, label: '去程' });
          if (flightInfo.returnNo) flights.push({ no: flightInfo.returnNo, date: flightInfo.returnDate || trip.endDate, label: '回程' });

          for (const f of flights) {
            const info = await searchFlightWithGoogleSearch(f.no, f.date);
            updatedBookings.push({
              id: Math.random().toString(36).substr(2, 9),
              type: BookingType.FLIGHT,
              title: `${f.label}: ${f.no}`,
              airline: info?.airline || '未知航空公司',
              date: f.date,
              time: info?.departureTime || '待定',
              location: info?.airport || '待確認機場',
              terminal: info?.terminal || '-',
              flightNumber: f.no.toUpperCase()
            });
          }
        }
      } else {
        const data: Booking = {
          id: editingBookingId || Math.random().toString(36).substr(2, 9),
          type: BookingType.ACCOMMODATION,
          title: accInfo.title,
          checkInDate: accInfo.checkIn,
          checkOutDate: accInfo.checkOut,
          location: accInfo.address || '未提供地址',
          date: accInfo.checkIn
        };
        updatedBookings = editingBookingId ? updatedBookings.map(b => b.id === editingBookingId ? data : b) : [...updatedBookings, data];
      }

      updateTrip({ ...trip, bookings: updatedBookings });
      setSyncStatus('success');
    } catch (e) {
      console.error(e);
      setSyncStatus('error');
    } finally {
      setIsBackgroundSyncing(false);
      resetForms();
      if (searchSources.length === 0) {
        setTimeout(() => setSyncStatus(null), 3000);
      }
    }
  };

  const resetForms = () => {
    const startDate = trip?.startDate || '';
    const endDate = trip?.endDate || '';
    setFlightInfo({ 
      outboundNo: '', 
      outboundDate: startDate, 
      returnNo: '', 
      returnDate: endDate 
    });
    setAccInfo({ 
      title: '', 
      checkIn: startDate, 
      checkOut: startDate, 
      address: '' 
    });
    setEditingBookingId(null);
  };

  const openFlightEdit = (booking: Booking) => {
    setEditingBookingId(booking.id);
    setNewBooking({ type: BookingType.FLIGHT });
    setFlightInfo({ 
      outboundNo: booking.flightNumber || '', 
      outboundDate: booking.date || trip.startDate, 
      returnNo: '', 
      returnDate: trip.endDate 
    });
    setIsModalOpen(true);
  };

  const openAccEdit = (booking: Booking) => {
    setEditingBookingId(booking.id);
    setNewBooking({ type: BookingType.ACCOMMODATION });
    setAccInfo({ 
      title: booking.title || '', 
      checkIn: booking.checkInDate || trip.startDate, 
      checkOut: booking.checkOutDate || trip.startDate, 
      address: booking.location || '' 
    });
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-8">
      <AnimatePresence>
        {(isBackgroundSyncing || syncStatus || searchSources.length > 0) && (
          <motion.div 
            initial={{ y: -50, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -50, opacity: 0 }}
            className="fixed top-4 left-1/2 -translate-x-1/2 z-[100] w-[90%] max-w-md"
          >
            <div className={`p-4 rounded-xl shadow-xl border transition-colors ${
              syncStatus === 'success' ? 'bg-[#00A86B] border-white/20 text-white' :
              syncStatus === 'error' ? 'bg-[#BC002D] border-white/20 text-white' :
              'bg-[#2D3436] border-white/5 text-white'
            }`}>
              <div className="flex items-center gap-3">
                {isBackgroundSyncing ? <Loader2 size={16} className="animate-spin" /> : 
                 syncStatus === 'success' ? <CheckCircle2 size={16} /> : <AlertTriangle size={16} />}
                <div className="flex-1">
                  <p className="text-[10px] font-black uppercase tracking-wider">
                    {isBackgroundSyncing ? '正在透過 Google 搜尋最新航班數據...' : syncStatus === 'success' ? '數據同步完成' : '同步失敗'}
                  </p>
                </div>
                {searchSources.length > 0 && !isBackgroundSyncing && (
                  <button onClick={() => { setSearchSources([]); setSyncStatus(null); }} className="text-[9px] font-bold opacity-60 uppercase">關閉</button>
                )}
              </div>

              {searchSources.length > 0 && !isBackgroundSyncing && (
                <div className="mt-3 pt-3 border-t border-white/10 space-y-2">
                  <p className="text-[9px] font-black uppercase opacity-60 tracking-widest">實時資訊來源：</p>
                  <div className="max-h-24 overflow-y-auto space-y-1 scrollbar-hide">
                    {searchSources.map((source, idx) => (
                      <a 
                        key={idx} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-between p-2 bg-white/5 hover:bg-white/10 rounded-lg transition-colors group"
                      >
                        <span className="text-[10px] font-bold truncate pr-4">{source.title || '航班數據源'}</span>
                        <ExternalLink size={10} className="shrink-0 opacity-40 group-hover:opacity-100" />
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black theme-text-contrast tracking-tight">預約管理</h1>
          <p className="text-[var(--text-muted)] text-xs font-bold uppercase tracking-widest mt-1">實時搜尋來源並翻譯資訊</p>
        </div>
      </div>

      <div className="space-y-10">
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="p-1.5 rounded-lg bg-blue-50 text-blue-500 shrink-0"><Plane size={16} /></div>
