        </AnimatePresence>
      </main>

      <nav className={`fixed bottom-0 left-0 right-0 z-50 px-1 py-1.5 shadow-lg border-t transition-colors duration-300
        ${theme === 'dark' ? 'bg-[#1E1E1E]/90 border-white/5' : 'bg-white/90 border-gray-100'} backdrop-blur-lg`}>
        <div className="max-w-xl mx-auto flex items-center justify-around">
          {navItems.map((item) => (
            <NavLink
              key={item.name}
              to={item.path}
              onClick={(e) => {
                if (item.path === '#') { e.preventDefault(); alert('請先建立旅程！'); }
                setIsSettingsOpen(false);
              }}
              className={({ isActive }) => `
                flex flex-col items-center gap-0.5 group px-2 py-1 transition-colors
                ${isActive && item.path !== '#' ? 'theme-primary' : 'text-gray-400'}
